// term: aiTeamNeeds
// id: aiPickPipelineAudit
// type: function
// subtype: Function
// page: transfermarktPage
// folder: unknown
// updatedAt: unknown
// codeField: funcBody
// dependencies: getTeamRatingsTransfermarkt.data | aiRunSeedState.value | filterTeam.value | getActivePlayersByTeam.data | teamIdentityOverrides.value | getCashFromSaisonstand.value
// extractionStatus: complete_or_primary_match
// AI Variance Configuration (Seeded)
// Central place defining team_variation_factor and corridor-sampling helpers.
// Used by aiTeamNeedsQuery (JS query) and aiTransferPicksBase (transformer).
//
// IMPORTANT:
//   - No Math.random() here (reactive transformer).
//   - Sampling is deterministic per run via aiRunSeedState (team + runId).
//
// Returns:
//   {
//     team_variation_factor: number,
//     cashUsageTarget: { center:number, min:number, max:number, sampled:number },
//     spendAggression: { center:number, min:number, max:number, sampled:number },
//     fitMinSoft: { center:number, min:number, max:number, sampled:number },
//     holeGate01: { center:number, min:number, max:number, sampled:number },
//     sampled_cashUsageTarget: number,
//     sampled_fitMinSoft: number,
//     sampled_holeGate01: number,
//     harmony: number,
//     ambition: number,
//     finances: number,
//     rosterCount: number,
//     thinRoster: boolean,
//     seedInt: number,
//     seedStr: string,
//
//     // (Added) budget debug helpers
//     budget_variation_seed: number,
//     budget_cap_u01: number
//   }

const trRows = (typeof formatDataAsArray === 'function' ?
formatDataAsArray({{ getTeamRatingsTransfermarkt.data }}) :
{{ getTeamRatingsTransfermarkt.data }}) || [];
const tr = trRows?.[0] || {};

const n = (v) => Number.isFinite(Number(v)) ? Number(v) : 0;
const clamp = (v, lo, hi) => Math.max(lo, Math.min(hi, v));

// ---------------------------
// Stable seed for this run
// ---------------------------
const seedState = {{ aiRunSeedState.value }} || null;
const team = String({{ filterTeam.value }} || '').trim();

const seedStr = String(seedState?.seedStr || `aiSearchSeed.v1::${team}::${Number(seedState?.runId || 0)}`);
let seedInt = Number(seedState?.seedInt);

// Fallback hashing (FNV-1a) if seedInt missing
const xfnv1a = (str) => {
  let h = 2166136261;
  const txt = String(str || '');
  for (let i = 0; i < txt.length; i++) {
    h ^= txt.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  return h >>> 0;
};

if (!Number.isFinite(seedInt) || seedInt <= 0) seedInt = xfnv1a(seedStr);

// Deterministic PRNG (mulberry32)
const mulberry32 = (a) => {
  let t = a >>> 0 || 1;
  return () => {
    t += 0x6D2B79F5;
    let x = t;
    x = Math.imul(x ^ x >>> 15, x | 1);
    x ^= x + Math.imul(x ^ x >>> 7, x | 61);
    return ((x ^ x >>> 14) >>> 0) / 4294967296;
  };
};

// We want stable but \"independent\" samples per corridor.
// So we derive per-key sub-seeds and create a small PRNG per sample.
const hash32 = (str) => xfnv1a(str);
const rand01ForKey = (key) => {
  const subSeed = (seedInt ^ hash32(String(key || '')) ^ 0x9E3779B9) >>> 0;
  const r = mulberry32(subSeed);
  return r();
};

const harmony = clamp(n(tr.harmony) || 4, 1, 10);
const ambition = clamp(n(tr.ambition) || 5, 1, 10);
const finances = clamp(n(tr.finances) || 5, 1, 10);

const roster = (typeof formatDataAsArray === 'function' ?
formatDataAsArray({{ getActivePlayersByTeam.data }}) :
{{ getActivePlayersByTeam.data }}) || [];
const rosterCount = Array.isArray(roster) ? roster.length : 0;

const teamIdentity = (() => {
  const teamCode = String({{ filterTeam.value }} || '').trim();
  const overrides = {{ teamIdentityOverrides.value }} || {};
  return overrides?.[teamCode] || overrides?.[teamCode.trim()] || null;
})();

const computeTeamVariationFactor = () => {
  const harmonyStrict01 = clamp((harmony - 1) / 9, 0, 1);
  const ambition01 = clamp((ambition - 1) / 9, 0, 1);
  const finances01 = clamp((finances - 1) / 9, 0, 1);

  const targetRoster = clamp(n(teamIdentity?.roster?.target) || 10, 7, 12);
  const fill01 = targetRoster > 0 ? clamp(rosterCount / targetRoster, 0, 1) : 0;
  const thin01 = fill01 < 0.75 ? 1 : fill01 < 0.90 ? 0.5 : 0;

  let v = 0.18;
  v -= 0.20 * harmonyStrict01;
  v += 0.12 * ambition01;
  v += 0.06 * finances01;
  v += 0.08 * thin01;

  const overrideV = teamIdentity?.variance?.team_variation_factor;
  if (Number.isFinite(n(overrideV))) v = n(overrideV);

  return clamp(v, 0.05, 0.60);
};

const team_variation_factor = computeTeamVariationFactor();

// Returns { center, min, max, sampled }
// NOTE: sampled uses seeded RNG based on a stable key.
const sampleCorridor = (key, center, min, max) => {
  const c = n(center);
  const lo = n(min);
  const hi = n(max);
  if (!(hi > lo)) return { center: c, min: lo, max: hi, sampled: c };

  const half = (hi - lo) / 2;
  const effHalf = half * team_variation_factor;
  const effLo = clamp(c - effHalf, lo, hi);
  const effHi = clamp(c + effHalf, lo, hi);

  const u = rand01ForKey(String(key || 'corridor'));
  const sampled = effLo + u * (effHi - effLo);

  return { center: c, min: lo, max: hi, sampled };
};

// Pre-compute the most important corridor samples so all consumers read identical values per render.

// 1) Budget / cash usage target
const budgetDiscipline = clamp((finances - 5) / 5, -1, 1);
const ambitionAggro = clamp((ambition - 5) / 5, -1, 1);
const salary_now = Array.isArray(roster) ?
roster.reduce((a, r) => a + n(r?.gehalt ?? r?.salary ?? r?.Gehalt ?? r?.gehalt_rechnung), 0) :
0;
const cash = n({{ getCashFromSaisonstand.value }}?.cash || 0);
const salary_runway = salary_now > 0 ? cash / salary_now : cash > 0 ? 99 : 0;
const runway01 = clamp((salary_runway - 2.0) / 5.0, 0, 1);

const spendAggressionCenter = clamp(
0.52 + 0.22 * ambitionAggro - 0.22 * budgetDiscipline + 0.10 * (runway01 - 0.5),
0.08,
0.95);


const spendAggressionCorridor = sampleCorridor(
'spendAggression',
spendAggressionCenter,
clamp(spendAggressionCenter - 0.07, 0.05, 0.95),
clamp(spendAggressionCenter + 0.07, 0.05, 0.95));


const cashUsageTargetCenter = clamp(
0.45 + 0.38 * spendAggressionCenter - 0.05 * budgetDiscipline + 0.06 * runway01,
0.45,
0.92);


const cashUsageTargetCorridor = sampleCorridor(
'cashUsageTarget',
cashUsageTargetCenter,
clamp(cashUsageTargetCenter - 0.06, 0.35, 0.92),
clamp(cashUsageTargetCenter + 0.06, 0.35, 0.92));


// 2) Fit strictness (derived from harmony step-function)
const fitSoftCenter =
harmony >= 10 ? 15 :
harmony >= 9 ? 12 :
harmony >= 8 ? 10 :
harmony >= 7 ? 8 :
harmony >= 6 ? 6 :
0;

const fitSoftCorridor = sampleCorridor(
'fitMinSoft',
fitSoftCenter,
Math.max(0, fitSoftCenter - 3),
fitSoftCenter + 3);


// 3) Discipline hole gate (thin roster)
const targetRosterSize = clamp(n(teamIdentity?.roster?.target) || 10, 7, 12);
const rosterFill01 = targetRosterSize > 0 ? clamp(rosterCount / targetRosterSize, 0, 1) : 0;
const thinRoster = rosterCount < Math.max(7, targetRosterSize - 2);
const holeGateCenter = thinRoster ? clamp(Math.pow(rosterFill01, 2), 0, 1) : 1;

const holeGateCorridor = sampleCorridor(
'holeGate01',
holeGateCenter,
clamp(holeGateCenter - (thinRoster ? 0.10 : 0), 0, 1),
clamp(holeGateCenter + (thinRoster ? 0.10 : 0), 0, 1));


// (Added) A stable draw specifically for budget-cap debugging (so we can see why a run landed on a value)
const budget_cap_u01 = rand01ForKey('budgetCap');

return {
  // public config consumed by aiTeamNeedsQuery and aiTransferPicksBase
  team_variation_factor: Number(team_variation_factor.toFixed(3)),

  // pre-sampled corridors (re-evaluated per reactive update, but deterministic per run)
  cashUsageTarget: cashUsageTargetCorridor,
  spendAggression: spendAggressionCorridor,
  fitMinSoft: fitSoftCorridor,
  holeGate01: holeGateCorridor,

  // convenience scalars (the actual sampled values used this run)
  sampled_cashUsageTarget: Number(n(cashUsageTargetCorridor.sampled).toFixed(3)),
  sampled_fitMinSoft: Number(n(fitSoftCorridor.sampled).toFixed(1)),
  sampled_holeGate01: Number(n(holeGateCorridor.sampled).toFixed(3)),

  // raw context (for debugging)
  harmony,
  ambition,
  finances,
  rosterCount,
  thinRoster,

  // seed debug
  seedInt,
  seedStr,

  // requested/needed for budget debugging
  budget_variation_seed: Number(seedInt),
  budget_cap_u01: Number(budget_cap_u01.toFixed(6)) };

// term: aiTeamNeeds
// id: aiPicksAudit
// type: function
// subtype: Function
// page: transfermarktPage
// folder: unknown
// updatedAt: unknown
// codeField: funcBody
// dependencies: aiTransferPackagesSnapshot.value | getCashFromSaisonstand.value | getActivePlayersByTeam.data
// extractionStatus: complete_or_primary_match
const pkgs = Array.isArray({{ aiTransferPackagesSnapshot.value }}) ? {{ aiTransferPackagesSnapshot.value }} : [];
const cash = Number({{ getCashFromSaisonstand.value }}?.cash || 0);
const roster = formatDataAsArray({{ getActivePlayersByTeam.data }}) || [];
const slotsLeft = Math.max(0, 12 - (roster?.length || 0));

const n = (v) => Number.isFinite(Number(v)) ? Number(v) : 0;

const overCash = pkgs.filter((p) => n(p.total_fee) > cash);
const overSlots = pkgs.filter((p) => n(p.player_count) > slotsLeft);
const infeasible = pkgs.filter((p) => !p.feasible);

return {
  packagesCount: pkgs.length,
  cash,
  slotsLeft,
  feasibleCount: pkgs.length - infeasible.length,
  infeasibleCount: infeasible.length,
  overCashCount: overCash.length,
  overSlotsCount: overSlots.length,
  examples: {
    top5: pkgs.slice(0, 5).map((p) => ({
      package_name: p.package_name,
      total_fee: n(p.total_fee),
      remaining_cash: n(p.remaining_cash),
      player_count: n(p.player_count),
      feasible: Boolean(p.feasible),
      package_score: n(p.package_score) })),

    overCash: overCash.slice(0, 5).map((p) => ({ package_name: p.package_name, total_fee: n(p.total_fee) })),
    overSlots: overSlots.slice(0, 5).map((p) => ({ package_name: p.package_name, player_count: n(p.player_count) })) } };

// term: aiPickSeasonPlan
// id: aiPickSeasonButton
// type: script
// subtype: ButtonWidget2
// page: Saisonstand
// folder: unknown
// updatedAt: unknown
// codeField: query
// dependencies: none
// extractionStatus: complete_or_primary_match
// Documentation:
//   Runs AI Season planning and saves ST1-10 lineups.
//   IMPORTANT SEASON BEHAVIOR (per app convention):
//   - Lineups are always persisted as season = 1.
//     This matches the manual lineup flow (which always writes season=1) so that saving
//     a lineup always overwrites the same slots and we never end up with parallel seasons
//     in the lineup table.
//
//   Performance:
//   - No global fatigue refresh here. (AI Season should be fast.)
//     Fatigue refresh is done only when explicitly requested (e.g. Base Score D1 flow).
//
//   Formkarten:
//   - We intentionally ignore formkarten_v2.is_used flags when feeding cards into the season planner,
//     because those flags can be out-of-sync and would cause "no cards assigned".
//
//   Engine inputs (patch):
//   - teamRatings: fetched and passed as soft bias (same as Preview)
//   - captainUsedCount: passed as hard remaining captain budget
//   - teamBiasByDiszi: precomputed via teamBiasForDiszi helper query
// Returns:
//   { ok: boolean, team: string, season: number, dryRun: boolean, savedSlots?: number, notes: string[] }
;

const t0 = Date.now();
const notes = [];

const s = (v) => String(v ?? '').trim();
const n = (v) => Number.isFinite(Number(v)) ? Number(v) : 0;
const clamp = (v, lo, hi) => Math.max(lo, Math.min(hi, v));
const normTeam = (x) => s(x).toUpperCase().replace(/\s*-\s*/g, '-');

const team = s(selectTeamEinsatzliste.value);

// 🔒 Force season=1 for lineup persistence.
const season = 1;
const dryRun = !!aiSeasonDryRun.value;

if (!team) {
  utils.showNotification({
    title: 'AI Season: Team fehlt',
    description: 'Bitte zuerst ein Team auswählen.',
    notificationType: 'warning' });

  return { ok: false, team, season, dryRun, notes: ['missing_team'] };
}

// Prefetch (extended with ratings + captain usage)
try {
  await Promise.all([
  getDiszireihenfolgeEinsatz.trigger(),
  getPunktetabelleQueryEinsatzliste.trigger(),
  getFormkartenPoolAllTeams.trigger(),
  getAllPlayersFromDB.trigger(),
  getTeamRatingsForSelectedTeam.trigger(),
  getTeamRatingsForSelectedTeam_viaSaisonstand.trigger(),
  getAllTeamCaptainUsage.trigger()]);

} catch (e) {
  console.warn('[aiPickSeasonPlan] prefetch failed', e);
  notes.push('prefetch_failed_some_inputs');
}

// Schedule
const disziRows = (formatDataAsArray(getDiszireihenfolgeEinsatz.data) || []).
map((r) => ({ name: s(r.disziplin), order: n(r.reihenfolge), players: clamp(n(r.player), 0, 12) })).
filter((r) => r.name && r.order > 0).
sort((a, b) => a.order - b.order);

const schedule = [...Array(10)].map((_, i) => {
  const st = i + 1;
  return {
    st,
    d1: disziRows[i * 2] ? { name: disziRows[i * 2].name, players: disziRows[i * 2].players } : null,
    d2: disziRows[i * 2 + 1] ? { name: disziRows[i * 2 + 1].name, players: disziRows[i * 2 + 1].players } : null };

});

if (schedule.some((r) => !r.d1 || !r.d2)) {
  utils.showNotification({
    title: 'AI Season: Disziplin-Schedule unvollständig',
    description: 'Für ST1–10 fehlen D1/D2 Disziplinen.',
    notificationType: 'error',
    duration: 6 });

  return { ok: false, team, season, dryRun, notes: [...notes, 'schedule_incomplete'] };
}

// Roster (robust name join)
const teamEsc = team.replace(/'/g, "''");
const rosterSql = `
  SELECT 
    ap.name,
    ap.team,
    p.klasse,
    p.pow, p.spe, p.men, p.soc,
    p.tdm, p.mini_dm, p.gewichtheben, p.hockey, p.breaking,
    p.staffel, p.time_trial, p.spurt, p.climbing, p.fechten,
    p.speed_schach as schach,
    p.takeshis_castle as takeshi,
    p.tennis,
    p.i_spy,
    p.wettessen,
    p.basketball,
    p.football,
    p.battlefield,
    p.eiskunstlauf as eiskunst,
    p.showcase
  FROM active_players ap
  LEFT JOIN "Player" p 
    ON regexp_replace(lower(trim(p.name)), '[^a-z0-9]', '', 'g')
     = regexp_replace(lower(trim(ap.name)), '[^a-z0-9]', '', 'g')
  WHERE ap.team IS NOT NULL
    AND regexp_replace(upper(trim(ap.team)), '[^A-Z0-9]', '', 'g')
        = regexp_replace(upper(trim('${teamEsc}')), '[^A-Z0-9]', '', 'g')
  ORDER BY ap.name;
`;

let roster = [];
try {
  dynamicSqlToExecute.setValue(rosterSql);
  await executeDynamicSql.trigger();
  roster = (formatDataAsArray(executeDynamicSql.data) || []).filter((p) => !!p?.name);
} catch (e) {
  utils.showNotification({
    title: 'AI Season: Kader-Fehler',
    description: String(e?.message || e),
    notificationType: 'error',
    duration: 6 });

  return { ok: false, team, season, dryRun, notes: [...notes, 'roster_sql_failed'] };
}

if (!roster.length) {
  utils.showNotification({
    title: 'AI Season: Kein Kader',
    description: `Für Team ${team} wurden keine active_players gefunden.`,
    notificationType: 'error',
    duration: 7 });

  return { ok: false, team, season, dryRun, notes: [...notes, 'no_roster_active_players'] };
}

// Cards
const colorMap = disziplinColorMapping.value || {};
const teamNorm = normTeam(team);

// IMPORTANT: ignore is_used by forcing used=false
const cards = (formatDataAsArray(getFormkartenPoolAllTeams.data) || []).
filter((r) => normTeam(r.team_code) === teamNorm).
map((r) => ({ id: n(r.id), v: n(r.card_value), c: s(r.card_color), used: false })).
filter((c) => c.id && c.v !== 0);

// Proxy teams
const globalPlayers = formatDataAsArray(getAllPlayersFromDB.data) || [];
const proxyTeams = {};
for (const p of globalPlayers) {
  const t = normTeam(p?.team);
  if (!t) continue;
  (proxyTeams[t] ||= []).push(p);
}

// --- Team Ratings (soft bias) ---
const ratingsDirect = (formatDataAsArray(getTeamRatingsForSelectedTeam.data) || [])[0] || null;
const ratingsVia = (formatDataAsArray(getTeamRatingsForSelectedTeam_viaSaisonstand.data) || [])[0] || null;
const ratingsRow = ratingsDirect || ratingsVia || null;

const teamRatings = ratingsRow ? {
  name: s(ratingsRow.name),
  power: n(ratingsRow.power),
  speed: n(ratingsRow.speed),
  mental: n(ratingsRow.mental),
  social: n(ratingsRow.social),
  ambition: n(ratingsRow.ambition),
  finances: n(ratingsRow.finances),
  board_confidence: n(ratingsRow.board_confidence),
  harmony: n(ratingsRow.harmony),
  manners: n(ratingsRow.manners),
  popularity: n(ratingsRow.popularity),
  cooperation: n(ratingsRow.cooperation) } :
null;

if (!teamRatings) notes.push('team_ratings_missing');

// --- Captain hard cap ---
// captainUsedCount = how many captains this team has ALREADY committed this season
const captainUsedCount = n(teamCaptainCount.value || 0);

// --- Precompute teamBiasByDiszi (do NOT trigger inside engine) ---
let teamBiasByDiszi = {};
try {
  if (teamRatings) {
    const disziNames = Array.from(new Set(
    schedule.flatMap((r) => [r?.d1?.name, r?.d2?.name]).filter(Boolean).map(String)));


    const biasResults = await Promise.all(
    disziNames.map(async (diszi) => {
      const disziColor = colorMap?.[diszi] || null;
      const res = await teamBiasForDiszi.trigger({
        additionalScope: { teamRatings, disziName: diszi, disziColor } });

      return [diszi, res];
    }));


    teamBiasByDiszi = Object.fromEntries(
    biasResults.
    filter(([name, val]) => !!name && val && typeof val === 'object').
    map(([name, val]) => [name, { bias: n(val.bias), reasons: Array.isArray(val.reasons) ? val.reasons : [] }]));

  }
} catch (e) {
  console.warn('[aiPickSeasonPlan] teamBiasByDiszi precompute failed', e);
  notes.push('team_bias_by_diszi_failed');
  teamBiasByDiszi = {};
}

// Engine
seasonPlannerEngineInput.setValue({
  team,
  season, // informational; persistence is still season=1
  roster,
  schedule,
  punktetabelleRows: formatDataAsArray(getPunktetabelleQueryEinsatzliste.data) || [],
  cards,
  disziColorMapping: colorMap,
  proxyTeams,
  teamRatings,
  captainUsedCount,
  teamBiasByDiszi });


let plan;
try {
  plan = await seasonPlannerEngine.trigger();
} catch (e) {
  utils.showNotification({
    title: 'AI Season: Engine Fehler',
    description: String(e?.message || e),
    notificationType: 'error',
    duration: 6 });

  return { ok: false, team, season, dryRun, notes: [...notes, 'engine_trigger_failed'] };
}

if (!plan?.ok || !Array.isArray(plan?.spieltage)) {
  utils.showNotification({
    title: 'AI Season: Plan ungültig',
    description: 'Engine lieferte kein gültiges Ergebnis.',
    notificationType: 'error',
    duration: 6 });

  return { ok: false, team, season, dryRun, notes: [...notes, 'engine_result_invalid'] };
}

seasonPlannerLastPlan.setValue(plan);
if (dryRun) {
  utils.showNotification({
    title: 'AI Season (Dry-Run)',
    description: `${team} · season=1 · Plan generiert`,
    notificationType: 'info',
    duration: 5 });

  notes.push(`runtime_ms:${Date.now() - t0}`);
  return { ok: true, team, season, dryRun: true, notes };
}

// ---- Score helpers (base + internal fatigue simulation) ----
// Note: This is only used to populate base/current/captain in the written lineup rows.
const fatigue = {};
for (const p of roster) fatigue[String(p.name)] = 0;

const fatigueMult = (count) =>
count >= 4 ? 0.8 :
count >= 3 ? 0.85 :
count >= 2 ? 0.9 :
count >= 1 ? 0.95 : 1.0;

const colForName = (name) => {
  const k = s(name).toLowerCase();
  const map = {
    'mini dm': 'mini_dm',
    mini_dm: 'mini_dm',
    'time trial': 'time_trial',
    time_trial: 'time_trial',
    'speed schach': 'schach',
    "takeshi's castle": 'takeshi',
    'takeshis castle': 'takeshi',
    takeshi: 'takeshi',
    'i spy': 'i_spy',
    i_spy: 'i_spy',
    eiskunstlauf: 'eiskunst' };

  return (map[k] || k).replace(/\s+/g, '_').replace(/-/g, '_');
};

const baseVal = (playerName, disziName) => {
  const p = roster.find((x) => String(x.name) === String(playerName));
  return p ? n(p?.[colForName(disziName)]) : 0;
};
const curVal = (playerName, disziName) =>
baseVal(playerName, disziName) * fatigueMult(n(fatigue[String(playerName)] || 0));

const sum = (arr, fn) => (Array.isArray(arr) ? arr : []).reduce((a, x) => a + fn(x), 0);
const best = (arr, fn) => {
  let b = 0;
  for (const x of Array.isArray(arr) ? arr : []) b = Math.max(b, fn(x));
  return b;
};

const escSql = (str) => String(str ?? '').replace(/'/g, "''");
const toCsv = (arr) => Array.isArray(arr) ? arr.map(String).join(', ') : '';
const toIntOrNull = (v) => {
  const x = Number(v);
  return Number.isFinite(x) && x !== 0 ? Math.trunc(x) : null;
};

const rows = [];
for (const st of plan.spieltage) {
  const spieltag = n(st?.spieltag);
  if (!spieltag) continue;

  const d1 = st?.d1;
  const d2 = st?.d2;

  const d1Diszi = s(d1?.disziplin);
  const d2Diszi = s(d2?.disziplin);

  const d1Players = d1?.playersPicked || [];
  const d2Players = d2?.playersPicked || [];

  const d1BaseX10 = Math.round(sum(d1Players, (nm) => baseVal(nm, d1Diszi)) * 10);
  const d2BaseX10 = Math.round(sum(d2Players, (nm) => baseVal(nm, d2Diszi)) * 10);

  const d1CurX10 = Math.round(sum(d1Players, (nm) => curVal(nm, d1Diszi)) * 10);
  const d2CurX10 = Math.round(sum(d2Players, (nm) => curVal(nm, d2Diszi)) * 10);

  const d1CapX10 = d1?.captain ? Math.round(best(d1Players, (nm) => curVal(nm, d1Diszi)) * 0.5 * 10) : 0;
  const d2CapX10 = d2?.captain ? Math.round(best(d2Players, (nm) => curVal(nm, d2Diszi)) * 0.5 * 10) : 0;

  rows.push({
    spieltag,
    disziplin_nr: 1,
    disziplin_name: d1Diszi,
    disziplin_color: s(d1?.disziplinColor) || null,
    players_csv: toCsv(d1Players),
    formkarte_1: toIntOrNull(d1?.formkarten?.[0] ?? null),
    formkarte_2: toIntOrNull(d1?.formkarten?.[1] ?? null),
