      red: n(srcPlan?.red || rosterColorCounts.red || 0),
      green: n(srcPlan?.green || rosterColorCounts.green || 0),
      blue: n(srcPlan?.blue || rosterColorCounts.blue || 0),
      yellow: n(srcPlan?.yellow || rosterColorCounts.yellow || 0)
    };

    const weakestAxes = Object.entries(axisCountsFromPlan)
      .sort((a, b) => n(a[1]) - n(b[1]))
      .map(([k]) => k);

    const weakestColors = Object.entries(colorCountsFromPlan)
      .sort((a, b) => n(a[1]) - n(b[1]))
      .map(([k]) => k);

    const explicitAxes = [
      lower(srcPlan?.primary_axis_need || ''),
      lower(srcPlan?.secondary_axis_need || '')
    ].filter((x) => ['pow', 'spe', 'men', 'soc'].includes(x));

    const explicitColors = [
      lower(srcPlan?.primary_color_need || ''),
      lower(srcPlan?.primary_card_need || '')
    ].filter((x) => ['red', 'green', 'blue', 'yellow'].includes(x));

    const explicitDiszi = lower(srcPlan?.primary_diszi_need || '');

    const chosenAxes = Array.from(new Set([
      ...explicitAxes,
      ...weakestAxes.slice(0, 2)
    ])).slice(0, 2);

    const chosenColors = Array.from(new Set([
      ...explicitColors,
      ...weakestColors.slice(0, 2)
    ])).slice(0, 2);

    if (explicitDiszi) {
      rows.push({
        need_type: 'discipline_hole',
        need_label: `Fallback discipline ${explicitDiszi}`,
        importance_score: 76,
        search_profile: { target_discipline_field: explicitDiszi }
      });
    }

    if (chosenAxes[0]) {
      rows.push({
        need_type: 'axis_upgrade',
        need_label: `Fallback axis ${chosenAxes[0]}`,
        importance_score: 72,
        search_profile: { axis_focus: chosenAxes[0] }
      });
    }

    if (chosenAxes[1]) {
      rows.push({
        need_type: 'axis_upgrade',
        need_label: `Fallback secondary axis ${chosenAxes[1]}`,
        importance_score: 60,
        search_profile: { axis_focus: chosenAxes[1] }
      });
    }

    if (chosenColors[0]) {
      rows.push({
        need_type: 'color_economy',
        need_label: `Fallback color ${chosenColors[0]}`,
        importance_score: 60,
        search_profile: { desired_class_color: chosenColors[0] }
      });
    }

    if (chosenColors[1]) {
      rows.push({
        need_type: 'color_economy',
        need_label: `Fallback secondary color ${chosenColors[1]}`,
        importance_score: 48,
        search_profile: { desired_class_color: chosenColors[1] }
      });
    }

    rows.push({
      need_type: 'historical_peak_opportunity',
      need_label: 'Fallback peak',
      importance_score: 54,
      search_profile: {}
    });

    rows.push({
      need_type: 'historical_breadth_opportunity',
      need_label: 'Fallback breadth',
      importance_score: 50,
      search_profile: {}
    });

    return rows;
  };

  let aiNeedRows = [];
  let needs_source = 'none';

  const needsFromSnapshot = coerceNeedRows(aiNeedsSnapshotRaw);
  const needsFromQuery = coerceNeedRows(aiNeedsQueryRaw);

  if (needsFromSnapshot.length) {
    aiNeedRows = needsFromSnapshot;
    needs_source = 'snapshot';
  } else if (needsFromQuery.length) {
    aiNeedRows = needsFromQuery;
    needs_source = 'query';
  }

  let used_needs_fallback = false;
  if (!aiNeedRows.length) {
    aiNeedRows = buildFallbackNeedRowsFromPlan(plan, baseRoster);
    used_needs_fallback = aiNeedRows.length > 0;
    if (used_needs_fallback) needs_source = 'fallback';
  }

  if (!aiNeedRows.length) {
    return emptyResult('empty_needs_and_no_fallback', {
      slot_plan_used: slotPlan,
      needs_rows_used: 0,
      used_needs_fallback,
      needs_source
    });
  }

  // ------------------------------------------------------------
  // Need parsing
  // ------------------------------------------------------------
  const extractAxis = (row) => {
    const type = lower(row?.need_type || row?.type || '');
    const slot = lower(row?.need_slot_key || row?.need_key || '');
    const label = lower(row?.need_label || row?.label || '');
    const profile = safeJson(row?.search_profile || row?.searchProfile || row?.profile || {});

    const direct = lower(profile?.axis_focus || profile?.axis || '');
    if (['pow', 'spe', 'men', 'soc'].includes(direct)) return direct;

    if (slot.startsWith('axis_')) return slot.replace(/^axis_/, '');

    const blob = [type, slot, label, lower(JSON.stringify(profile))].join(' | ');
    if (blob.includes('pow')) return 'pow';
    if (blob.includes('spe')) return 'spe';
    if (blob.includes('men')) return 'men';
    if (blob.includes('soc')) return 'soc';
    return '';
  };

  const extractColor = (row) => {
    const type = lower(row?.need_type || row?.type || '');
    const slot = lower(row?.need_slot_key || row?.need_key || '');
    const label = lower(row?.need_label || row?.label || '');
    const profile = safeJson(row?.search_profile || row?.searchProfile || row?.profile || {});

    const direct = lower(profile?.desired_class_color || profile?.color || '');
    if (['red', 'green', 'blue', 'yellow'].includes(direct)) return direct;

    if (slot.startsWith('color_')) return slot.replace(/^color_/, '');
    if (slot.startsWith('card_')) return slot.replace(/^card_/, '');

    const blob = [type, slot, label, lower(JSON.stringify(profile))].join(' | ');
    if (blob.includes('yellow')) return 'yellow';
    if (blob.includes('blue')) return 'blue';
    if (blob.includes('green')) return 'green';
    if (blob.includes('red')) return 'red';
    return '';
  };

  const extractDiszi = (row) => {
    const type = lower(row?.need_type || row?.type || '');
    const slot = lower(row?.need_slot_key || row?.need_key || '');
    const label = lower(row?.need_label || row?.label || '');
    const profile = safeJson(row?.search_profile || row?.searchProfile || row?.profile || {});

    const direct = lower(
      profile?.target_discipline_field ||
      profile?.discipline ||
      profile?.diszi ||
      ''
    );
    if (direct) return direct;
    if (slot.startsWith('diszi_')) return slot.replace(/^diszi_/, '');

    const blob = [type, slot, label, lower(JSON.stringify(profile))].join(' | ');
    for (const d of disciplineKeys) {
      if (blob.includes(d)) return d;
    }
    return '';
  };

  const parseNeedRows = (rows) => {
    return (Array.isArray(rows) ? rows : [])
      .map((row) => {
        const type = lower(row?.need_type || row?.type || '');
        const label = s(row?.need_label || row?.label || row?.name || '');
        const importance = n(row?.importance_score || row?.importance || row?.score || 0);
        const profile = safeJson(row?.search_profile || row?.searchProfile || row?.profile || {});

        if (importance <= 0) return null;

        if (type === 'axis_upgrade' || type.includes('axis')) {
          return {
            family: 'axis',
            label,
            importance,
            axis: extractAxis(row),
            profile
          };
        }

        if (type === 'discipline_hole' || type.includes('discipline') || type.includes('diszi')) {
          return {
            family: 'diszi',
            label,
            importance,
            diszi: extractDiszi(row),
            profile
          };
        }

        if (type === 'color_economy' || type.includes('economy') || type.includes('color') || type.includes('card')) {
          return {
            family: 'card',
            label,
            importance,
            color: extractColor(row),
            profile
          };
        }

        if (type === 'historical_peak_opportunity') {
          return {
            family: 'peak',
            label,
            importance,
            profile
          };
        }

        if (type === 'historical_breadth_opportunity') {
          return {
            family: 'breadth',
            label,
            importance,
            profile
          };
        }

        return null;
      })
      .filter(Boolean);
  };

  const parsedNeeds = parseNeedRows(aiNeedRows);

  if (!parsedNeeds.length) {
    return emptyResult('no_parsed_needs', {
      slot_plan_used: slotPlan,
      needs_rows_used: Array.isArray(aiNeedRows) ? aiNeedRows.length : 0,
      used_needs_fallback,
      needs_source
    });
  }

  // ------------------------------------------------------------
  // Simulated roster state
  // ------------------------------------------------------------
  const axisCounts = { pow: 0, spe: 0, men: 0, soc: 0 };
  const colorCounts = { red: 0, green: 0, blue: 0, yellow: 0 };
  const cardCounts = { red: 0, green: 0, blue: 0, yellow: 0 };
  const disziCounts = {};

  for (const p of baseRoster) {
    const ax = getAxis(p);
    const col = getColor(p);

    if (ax && axisCounts[ax] != null) axisCounts[ax] += 1;
    if (col && colorCounts[col] != null) {
      colorCounts[col] += 1;
      cardCounts[col] += 2;
    }

    const dz = lower(p?.discipline || p?.diszi || p?.disziplin || '');
    if (dz) disziCounts[dz] = (disziCounts[dz] || 0) + 1;
  }

  // ------------------------------------------------------------
  // Budget / lanes
  // ------------------------------------------------------------
  let remainingBudget = n(plan.allowed_budget_for_search);

  const buildBudgetTracksFallback = (slotPlanArr, totalBudget) => {
    const tracks = { star: 0, core: 0, depth: 0, reserve: 0, diszi: 0 };
    const cnt = Array.isArray(slotPlanArr) ? slotPlanArr.length : 0;
    if (cnt <= 0 || totalBudget <= 0) return tracks;

    const perSlot = totalBudget / Math.max(1, cnt);

    for (const role of slotPlanArr) {
      const r = lower(role);
      if (tracks[r] == null) continue;
      tracks[r] += perSlot;
    }

    return Object.fromEntries(
      Object.entries(tracks).map(([k, v]) => [k, Number(n(v).toFixed(2))])
    );
  };

  const budgetTracksFallback = buildBudgetTracksFallback(
    slotPlan,
    n(plan.allowed_budget_for_search)
  );

  const rawBudgetTracks = plan?.budget_tracks || {};
  const budget_tracks = {
    star: n(rawBudgetTracks?.star || budgetTracksFallback.star || 0),
    core: n(rawBudgetTracks?.core || budgetTracksFallback.core || 0),
    depth: n(rawBudgetTracks?.depth || budgetTracksFallback.depth || 0),
    reserve: n(rawBudgetTracks?.reserve || budgetTracksFallback.reserve || 0),
    diszi: n(rawBudgetTracks?.diszi || budgetTracksFallback.diszi || 0)
  };

  const coerceActiveLanes = (src, slotPlanArr, tracks) => {
    if (Array.isArray(src)) {
      return Array.from(new Set(src.map((x) => lower(x)).filter(Boolean)));
    }

    if (src && typeof src === 'object') {
      const numericKeys = Object.keys(src)
        .filter((k) => /^\d+$/.test(String(k)))
        .map((k) => Number(k))
        .sort((a, b) => a - b);

      if (numericKeys.length) {
        return Array.from(new Set(numericKeys.map((k) => lower(src[k])).filter(Boolean)));
      }
    }

    const fromSlotPlan = Array.from(new Set(
      (Array.isArray(slotPlanArr) ? slotPlanArr : []).map((x) => lower(x)).filter(Boolean)
    ));

    if (fromSlotPlan.length) return fromSlotPlan;

    return Object.keys(tracks).filter((k) => n(tracks[k]) > 0);
  };

  const activeLanes = coerceActiveLanes(plan?.active_lanes, slotPlan, budget_tracks);

  const laneSpent = { star: 0, core: 0, depth: 0, reserve: 0, diszi: 0 };
  const lanePickCounts = { star: 0, core: 0, depth: 0, reserve: 0, diszi: 0 };
  const pickedNames = new Set();
  const picks = [];

  const isLaneActive = (lane) => activeLanes.includes(lower(lane));

  const laneCountFromPlan = (track) => {
    const t = lower(track);
    const direct =
      t === 'star' ? n(plan?.star_slots_remaining) :
      t === 'core' ? n(plan?.core_slots_remaining) :
      t === 'depth' ? n(plan?.depth_slots_remaining) :
      t === 'reserve' ? n(plan?.reserve_slots_remaining) :
      t === 'diszi' ? n(plan?.diszi_slots_remaining) :
      0;

    return Math.max(0, direct || n(slotPlanCounts[t] || 0));
  };

  const laneSlotsRemaining = (track) => {
    const t = lower(track);
    return Math.max(0, laneCountFromPlan(t) - n(lanePickCounts[t] || 0));
  };

  const laneBudgetRemaining = (track) => {
    const t = lower(track);
    const laneBudgetTotal = n(budget_tracks?.[t] || 0);
    const raw = Math.max(0, laneBudgetTotal - n(laneSpent?.[t] || 0));
    return Math.max(0, Math.min(raw, remainingBudget));
  };

  const hasLaneCapacity = (track) => {
    const t = lower(track);
    return isLaneActive(t) && laneSlotsRemaining(t) > 0 && laneBudgetRemaining(t) > 0;
  };

  const resolveUsableTrack = (requestedTrack) => {
    const t = lower(requestedTrack);
    if (hasLaneCapacity(t)) return t;

    const fallbackMap = {
      star: ['core', 'depth', 'reserve', 'diszi'],
      core: ['depth', 'reserve', 'diszi', 'star'],
      depth: ['reserve', 'core', 'diszi', 'star'],
      reserve: ['depth', 'core', 'diszi', 'star'],
      diszi: ['depth', 'core', 'reserve', 'star']
    };

    const order = fallbackMap[t] || ['depth', 'core', 'reserve', 'diszi', 'star'];

    for (const lane of order) {
      if (hasLaneCapacity(lane)) return lane;
    }

    return '';
  };

  const computeMarketRoleAnchor = (track, budgetCap) => {
    const pref = preferredBracketWindow(track);

    let pool = rawCandidates
      .filter((c) => !pickedNames.has(lower(c?.name || '')))
      .map((c) => ({
        price: n(c?.marktwert || c?.market_value || c?.mw || c?.MW || 0),
        bracket: getPlayerBracket(c)
      }))
      .filter((x) => x.price > 0 && x.price <= Math.max(0, n(budgetCap)));

    if (!pool.length) return { min: 0, target: 0, max: 0, count: 0 };

    let rolePool = pool.filter((x) => n(x.bracket) >= n(pref.min) && n(x.bracket) <= n(pref.max));
    if (rolePool.length < 4) {
      rolePool = pool.filter((x) => n(x.bracket) >= n(pref.min) - 1 && n(x.bracket) <= n(pref.max) + 1);
    }
    if (rolePool.length < 4) rolePool = pool;

    const prices = rolePool.map((x) => n(x.price)).filter((x) => x > 0);
    if (!prices.length) return { min: 0, target: 0, max: 0, count: 0 };

    return {
      min: Number(quantile(prices, 0.20).toFixed(2)),
      target: Number(quantile(prices, 0.50).toFixed(2)),
      max: Number(quantile(prices, 0.85).toFixed(2)),
      count: prices.length
    };
  };

  const computeLaneBudgetContext = (requestedTrack) => {
    const track = resolveUsableTrack(requestedTrack);

    if (!track) {
      return {
        budget_track: '',
        lane_budget_total: 0,
        lane_budget_remaining: 0,
        lane_slots_remaining: 0,
        lane_target_fee: 0,
        lane_min_fee: 0,
        lane_max_fee: 0,
        effective_pick_cap: 0,
        preferred_bracket_min: 0,
        preferred_bracket_max: 0,
        market_role_min_fee: 0,
        market_role_target_fee: 0,
        market_role_max_fee: 0,
        market_role_pool_count: 0
      };
    }

    const lane_budget_total = n(budget_tracks?.[track] || 0);
    const lane_budget_remaining = laneBudgetRemaining(track);
    const lane_slots_remaining = laneSlotsRemaining(track);

    if (lane_budget_remaining <= 0 || lane_slots_remaining <= 0) {
      return {
        budget_track: track,
        lane_budget_total,
        lane_budget_remaining,
        lane_slots_remaining,
        lane_target_fee: 0,
        lane_min_fee: 0,
        lane_max_fee: 0,
        effective_pick_cap: 0,
        preferred_bracket_min: 0,
        preferred_bracket_max: 0,
        market_role_min_fee: 0,
        market_role_target_fee: 0,
        market_role_max_fee: 0,
        market_role_pool_count: 0
      };
    }

    const budget_target_fee = lane_budget_remaining / Math.max(1, lane_slots_remaining);
    const marketRole = computeMarketRoleAnchor(track, Math.min(lane_budget_remaining, remainingBudget));
    const pref = preferredBracketWindow(track);

    let lane_target_fee = budget_target_fee;
    let lane_min_fee = 0;
    let lane_max_fee = 0;

    if (marketRole.count > 0) {
      const marketTarget = n(marketRole.target);

      lane_target_fee = marketTarget > 0
        ? Math.min(Math.max(marketRole.min, marketTarget), lane_budget_remaining, remainingBudget)
        : Math.min(budget_target_fee, lane_budget_remaining, remainingBudget);

      lane_min_fee = Math.min(n(marketRole.min), lane_target_fee);
      lane_max_fee = Math.min(
        Math.max(n(marketRole.max), lane_target_fee),
        lane_budget_remaining,
        remainingBudget
      );
    } else {
      const mult = (() => {
        const t = lower(track);
        if (t === 'star') return { min: 0.60, max: 1.35 };
        if (t === 'core') return { min: 0.65, max: 1.25 };
        if (t === 'depth') return { min: 0.35, max: 1.10 };
        if (t === 'reserve') return { min: 0.35, max: 1.00 };
        if (t === 'diszi') return { min: 0.50, max: 1.20 };
        return { min: 0.35, max: 1.10 };
      })();

      lane_target_fee = Math.min(budget_target_fee, lane_budget_remaining, remainingBudget);
      lane_min_fee = lane_target_fee * n(mult.min);
      lane_max_fee = Math.min(lane_target_fee * n(mult.max), lane_budget_remaining, remainingBudget);
    }

    const effective_pick_cap = Math.max(
      0,
      Math.min(remainingBudget, lane_budget_remaining, lane_max_fee > 0 ? lane_max_fee : remainingBudget)
    );

    return {
      budget_track: track,
      lane_budget_total,
      lane_budget_remaining,
      lane_slots_remaining,
      lane_target_fee,
      lane_min_fee,
      lane_max_fee,
      effective_pick_cap,
      preferred_bracket_min: n(pref.min),
      preferred_bracket_max: n(pref.max),
      market_role_min_fee: n(marketRole.min),
      market_role_target_fee: n(marketRole.target),
      market_role_max_fee: n(marketRole.max),
      market_role_pool_count: n(marketRole.count)
    };
  };

  // ------------------------------------------------------------
  // Dynamic need evaluation
  // ------------------------------------------------------------
  const evalDynamicNeed = (need, plannedRole) => {
    const simRosterSize = Math.max(1, baseRoster.length + picks.length);

    if (need.family === 'axis') {
      const axis = lower(need.axis || '');
      const desiredShare = clamp(n(need.profile?.desired_share || 0.25), 0, 1);
      const currentShare = axis && axisCounts[axis] != null
        ? clamp(n(axisCounts[axis]) / simRosterSize, 0, 1)
        : 0;

      const gap01 = clamp(desiredShare - currentShare, 0, 1);
      const primaryBoost = axis && axis === lower(plan.primary_axis_need || '') ? 8 : 0;
      const dynamicImportance = n(need.importance) * (0.50 + 0.50 * gap01) + primaryBoost;

      return { ...need, dynamicImportance, meta: { gap01, currentShare, desiredShare } };
    }

    if (need.family === 'diszi') {
      const d = lower(need.diszi || '');
      const cnt = n(disziCounts[d] || 0);
      const gapFactor = cnt <= 0 ? 1 : cnt === 1 ? 0.60 : 0.25;
      const primaryBoost = d && d === lower(plan.primary_diszi_need || '') ? 8 : 0;
      const dynamicImportance = n(need.importance) * gapFactor + primaryBoost;

      return { ...need, dynamicImportance, meta: { currentCount: cnt, gapFactor } };
    }

    if (need.family === 'card') {
      const c = lower(need.color || '');
      const cards = n(cardCounts[c] || 0);
      const gapFactor = cards <= 2 ? 1 : cards <= 4 ? 0.65 : 0.25;
      const primaryBoost =
        c && (c === lower(plan.primary_color_need || '') || c === lower(plan.primary_card_need || ''))
          ? 8
          : 0;

      const dynamicImportance = n(need.importance) * gapFactor + primaryBoost;
      return { ...need, dynamicImportance, meta: { currentCards: cards, gapFactor } };
    }

    if (need.family === 'peak') {
      const roleBoost = ['core', 'star'].includes(lower(plannedRole)) ? 1.0 : 0.60;
      return { ...need, dynamicImportance: n(need.importance) * roleBoost, meta: { roleBoost } };
    }

    if (need.family === 'breadth') {
      const roleBoost = ['reserve', 'depth'].includes(lower(plannedRole)) ? 1.0 : 0.60;
      return { ...need, dynamicImportance: n(need.importance) * roleBoost, meta: { roleBoost } };
    }

    return { ...need, dynamicImportance: n(need.importance), meta: {} };
  };

  const roleFamilyBias = {
    reserve: { card: 18, breadth: 14, axis: -3, diszi: -4, peak: -6 },
    depth:   { axis: 14, diszi: 11, card: 2, breadth: 1, peak: 0 },
    core:    { axis: 20, peak: 14, diszi: 7, card: -4, breadth: -6 },
    star:    { peak: 20, axis: 12, diszi: 4, card: -6, breadth: -8 },
    diszi:   { diszi: 20, axis: 4, card: -2, breadth: -3, peak: 0 }
  };

  const getEvaluatedNeeds = (plannedRole) => {
    const role = lower(plannedRole || 'depth');
    const bias = roleFamilyBias[role] || roleFamilyBias.depth;

    return parsedNeeds
      .map((need) => {
        const ev = evalDynamicNeed(need, role);
        const familyBonus = n(bias[lower(ev.family)] || 0);

        return {
          ...ev,
          roleBiasScore: familyBonus,
          roleWeightedImportance: n(ev.dynamicImportance) + familyBonus
        };
      })
      .sort((a, b) => {
        const delta = n(b.roleWeightedImportance) - n(a.roleWeightedImportance);
        if (Math.abs(delta) > 6) return delta;
        return n(b.dynamicImportance) - n(a.dynamicImportance);
      });
  };

  const pickTopNeedForRole = (evaluatedNeeds, plannedRole) => {
    const role = lower(plannedRole || 'depth');

    const familiesByRole = {
      core: ['axis', 'peak', 'diszi'],
      depth: ['axis', 'diszi', 'card'],
      reserve: ['card', 'breadth'],
      diszi: ['diszi'],
      star: ['peak', 'axis']
    };

    const preferred = familiesByRole[role] || ['axis', 'diszi', 'card'];

    const strictPool = evaluatedNeeds.filter((x) => preferred.includes(lower(x.family)));
    const fallbackPool = evaluatedNeeds;

    if ((role === 'reserve' || role === 'diszi') && strictPool.length) {
      return {
        topNeed: strictPool[0],
        selectionMode: `strict_${role}`
      };
    }

    if ((role === 'core' || role === 'star') && strictPool.length) {
      const strictTop = strictPool[0];
      const allTop = fallbackPool[0];

      if (n(strictTop.roleWeightedImportance) >= n(allTop.roleWeightedImportance) - 8) {
        return {
          topNeed: strictTop,
          selectionMode: `preferred_${role}`
        };
      }
    }

    if (role === 'depth' && strictPool.length) {
      return {
        topNeed: strictPool[0],
        selectionMode: 'preferred_depth'
      };
    }

    return {
      topNeed: fallbackPool[0] || null,
      selectionMode: 'default'
    };
  };

  // ------------------------------------------------------------
  // Strategic focus matching
  // ------------------------------------------------------------
  const focusTokens = [
    s(plan.strategic_focus_primary || ''),
    s(plan.strategic_focus_secondary || '')
  ].filter(Boolean);

  const candidateMatchesFocus = (c, focusToken) => {
    const token = lower(focusToken);
    const candAxis = getAxis(c);
    const candColor = getColor(c);
    const candBestDiszi = getBestDiszi(c);

    if (!token) return false;
    if (['pow', 'spe', 'men', 'soc'].includes(token)) return candAxis === token;
    if (token.startsWith('color_')) return candColor === token.replace(/^color_/, '');
    if (token.startsWith('card_')) return candColor === token.replace(/^card_/, '');
    if (token.startsWith('diszi_')) return candBestDiszi === token.replace(/^diszi_/, '');

    return false;
  };

  const candidateNeedCoverage = (c, need) => {
    const candAxis = getAxis(c);
    const candColor = getColor(c);
    const candBestDiszi = getBestDiszi(c);

    if (need.family === 'axis') return candAxis === lower(need.axis || '') ? 1 : 0;
    if (need.family === 'card') return candColor === lower(need.color || '') ? 1 : 0;

    if (need.family === 'diszi') {
      const d = lower(need.diszi || '');
      if (candBestDiszi === d) return 1;
      return getDisziScore(c, d) >= 65 ? 0.6 : 0;
    }

    if (need.family === 'peak') return getPeakScore(c) >= 20 ? 1 : getPeakScore(c) >= 12 ? 0.5 : 0;
    if (need.family === 'breadth') return getVersatilityScore(c) >= 18 ? 1 : getVersatilityScore(c) >= 10 ? 0.5 : 0;

    return 0;
  };

  // ------------------------------------------------------------
  // Candidate scoring
  // ------------------------------------------------------------
  const teamVariationFactor = n(aiVarianceCfg?.team_variation_factor || 0);

  const scoreCandidate = (c, need, evaluatedNeeds, laneCtx, plannedRole, pick_nr) => {
    const price = n(c?.marktwert || c?.market_value || c?.mw || c?.MW || 0);
    if (price <= 0) return { score: -Infinity };

    const effectiveCap = Math.max(0, n(laneCtx?.effective_pick_cap || 0));
    if (effectiveCap <= 0) return { score: -Infinity };
    if (price > effectiveCap + 0.001) return { score: -Infinity };
    if (price > remainingBudget + 0.001) return { score: -Infinity };

    const target = Math.max(0.01, n(laneCtx?.lane_target_fee || 0));
    const laneMin = Math.max(0, n(laneCtx?.lane_min_fee || 0));
    const laneMax = Math.max(0, n(laneCtx?.lane_max_fee || 0));
    if (laneMax > 0 && price > laneMax + 0.001) return { score: -Infinity };

    const { pow, spe, men, soc, core } = candidateCore(c);
    const fit = n(c?.team_fit || c?.fit || 0);
    const peakScore = getPeakScore(c);
    const versatilityScore = getVersatilityScore(c);
    const candAxis = getAxis(c);
    const candColor = getColor(c);
    const candBestDiszi = getBestDiszi(c);

    let posMatch = 0.25;
    let qualityForNeed = core;

    if (need.family === 'axis') {
      const axis = lower(need.axis || '');
      posMatch = candAxis === axis ? 1.0 : 0.35;
      qualityForNeed =
        axis === 'pow' ? pow :
        axis === 'spe' ? spe :
        axis === 'men' ? men :
        axis === 'soc' ? soc :
        core;
    }

    else if (need.family === 'diszi') {
      const d = lower(need.diszi || '');
      const disziScore = getDisziScore(c, d);
      posMatch = candBestDiszi === d ? 1.0 : disziScore > 0 ? 0.60 : 0.25;
      qualityForNeed = disziScore > 0 ? disziScore : core * 0.60;
    }

    else if (need.family === 'card') {
      const color = lower(need.color || '');
      posMatch = candColor === color ? 1.0 : 0.25;
      qualityForNeed = core * 0.55 + versatilityScore * 0.45;
    }

    else if (need.family === 'peak') {
      posMatch = 1.0;
      qualityForNeed = peakScore * 3.1 + core * 0.35;
    }

    else if (need.family === 'breadth') {
      posMatch = 1.0;
      qualityForNeed = versatilityScore * 2.2 + core * 0.45;
    }

    const deviation01 = Math.abs(price - target) / Math.max(target, 0.01);
    const budget_fit_score = clamp(1 - deviation01, 0, 1) * 12;

    const player_bracket = getPlayerBracket(c);
    const preferred_bracket_min = n(laneCtx?.preferred_bracket_min || 0);
    const preferred_bracket_max = n(laneCtx?.preferred_bracket_max || 0);
    const bracket_fit_score = computeBracketFitScore(player_bracket, preferred_bracket_min, preferred_bracket_max);

    const isStarOrCore = ['star', 'core'].includes(lower(laneCtx?.budget_track || ''));

    const under = laneMin > 0 && price < laneMin;
    const underRatio = under ? (laneMin - price) / Math.max(laneMin, 0.01) : 0;
    const under_spend_penalty = under && isStarOrCore ? clamp(underRatio, 0, 1) * 18 : 0;

    let over_spend_penalty = 0;
    if (laneMax > 0 && price > laneMax) {
      const overRatio = (price - laneMax) / Math.max(laneMax, 0.01);
      over_spend_penalty = clamp(overRatio, 0, 1) * 30;
    }

    const depthBonus =
      lower(plannedRole) === 'depth' && effectiveCap > 0
        ? clamp((effectiveCap - price) / Math.max(effectiveCap, 1), 0, 1) * 4
        : 0;

    const matchedFocuses = focusTokens.filter((token) => candidateMatchesFocus(c, token));
    const multi_need_bonus =
      (matchedFocuses.length >= 1 ? 1.5 : 0) +
      Math.max(0, matchedFocuses.length - 1) * 3;

    const secondary_need_bonus = evaluatedNeeds
      .slice(1, 4)
      .reduce((acc, nd) => {
        const cover = candidateNeedCoverage(c, nd);
        const value = Math.min(4, n(nd.roleWeightedImportance) * 0.04);
        return acc + cover * value;
      }, 0);

    const jitterKey = [
      plan.team_plan_seed,
      teamVariationFactor,
      pick_nr,
      s(c?.name || ''),
      lower(plannedRole || ''),
      lower(need.family || ''),
      lower(need.axis || need.color || need.diszi || '')
    ].join('|');

    const score_jitter = (rand01FromKey(jitterKey) - 0.5) * (1.2 + teamVariationFactor * 2);

    const score =
      qualityForNeed * 0.30 * posMatch +
      fit * 0.18 +
      budget_fit_score +
      bracket_fit_score +
      depthBonus +
      multi_need_bonus +
      secondary_need_bonus +
      score_jitter -
      under_spend_penalty -
      over_spend_penalty;

    return {
      score,
      budget_fit_score,
      under_spend_penalty,
      over_spend_penalty,
      player_bracket: player_bracket ?? null,
      preferred_bracket_min: preferred_bracket_min || null,
      preferred_bracket_max: preferred_bracket_max || null,
      bracket_fit_score: Number(n(bracket_fit_score).toFixed(2)),
      matchedFocuses,
      multi_need_bonus: Number(n(multi_need_bonus).toFixed(2)),
      secondary_need_bonus: Number(n(secondary_need_bonus).toFixed(2)),
      score_jitter: Number(n(score_jitter).toFixed(3))
    };
  };

  // ------------------------------------------------------------
  // Simulation loop
  // ------------------------------------------------------------
  for (let pick_nr = 1; pick_nr <= slots_max; pick_nr++) {
    if (remainingBudget <= 0) break;

    const plannedRole = Array.isArray(slotPlan) ? slotPlan[pick_nr - 1] ?? null : null;
    const requestedTrack = plannedRole != null ? plannedRole : 'depth';

    const laneCtx = computeLaneBudgetContext(requestedTrack);

    if (
      !laneCtx?.budget_track ||
      n(laneCtx.effective_pick_cap) <= 0 ||
      n(laneCtx.lane_slots_remaining) <= 0
    ) {
      break;
    }

    const budgetTrack = laneCtx.budget_track;
    const evaluatedNeeds = getEvaluatedNeeds(plannedRole || budgetTrack);
    const pickedNeed = pickTopNeedForRole(evaluatedNeeds, plannedRole || budgetTrack);
    const topNeed = pickedNeed?.topNeed || null;
    const top_need_selection_mode = s(pickedNeed?.selectionMode || 'default');

    if (!topNeed) break;

    let bestCandidate = null;
    let bestExplain = null;
    let bestScore = -Infinity;

    for (const c of rawCandidates) {
      const cname = lower(c?.name || '');
      if (!cname || pickedNames.has(cname)) continue;

      const res = scoreCandidate(c, topNeed, evaluatedNeeds, laneCtx, plannedRole || budgetTrack, pick_nr);
      const sc = n(res?.score);

      if (sc > bestScore) {
        bestScore = sc;
        bestCandidate = c;
        bestExplain = res;
      }
    }

    if (!bestCandidate || !bestExplain || !Number.isFinite(bestScore)) break;

    const price = n(bestCandidate?.marktwert || bestCandidate?.market_value || bestCandidate?.mw || bestCandidate?.MW || 0);
    const effective_pick_cap = n(laneCtx.effective_pick_cap);

    if (
      price <= 0 ||
      price > remainingBudget + 0.001 ||
      price > effective_pick_cap + 0.001 ||
      price > n(laneCtx.lane_max_fee) + 0.001
    ) {
      break;
    }

    pickedNames.add(lower(bestCandidate?.name || ''));

    remainingBudget = Number((remainingBudget - price).toFixed(2));

    laneSpent[budgetTrack] = Number((n(laneSpent[budgetTrack]) + price).toFixed(2));
    lanePickCounts[budgetTrack] = n(lanePickCounts[budgetTrack]) + 1;

    const candAxis = getAxis(bestCandidate);
    const candColor = getColor(bestCandidate);
    const candBestDiszi = getBestDiszi(bestCandidate);

    if (candAxis && axisCounts[candAxis] != null) axisCounts[candAxis] += 1;

    if (candColor && colorCounts[candColor] != null) {
      colorCounts[candColor] += 1;
      cardCounts[candColor] += 2;
    }

    if (candBestDiszi) {
      disziCounts[candBestDiszi] = (disziCounts[candBestDiszi] || 0) + 1;
    }

    const slot_role_fallback_used = Boolean(
      plannedRole &&
      budgetTrack &&
      lower(plannedRole) !== lower(budgetTrack)
    );

    const slot_role_fallback_reason = slot_role_fallback_used
      ? 'planned_track_inactive_or_exhausted'
      : '';

    const rationale = [
      `Planned role ${s(plannedRole || '—')}, used ${s(budgetTrack || '—')}.`,
      `Need: ${s(topNeed.label || topNeed.family || '—')}.`,
      `Mode ${top_need_selection_mode}.`,
      `Price ${fmtM(price)} vs target ${fmtM(laneCtx.lane_target_fee)}, cap ${fmtM(effective_pick_cap)}.`,
      `Market role band ${fmtM(laneCtx.market_role_min_fee)}-${fmtM(laneCtx.market_role_max_fee)}.`,
      `Bracket ${bestExplain.player_bracket ?? '—'}, fit ${n(bestExplain.bracket_fit_score).toFixed(2)}.`,
      `Focus matches ${bestExplain.matchedFocuses?.length || 0}, secondary bonus ${n(bestExplain.secondary_need_bonus).toFixed(2)}, jitter ${n(bestExplain.score_jitter).toFixed(3)}.`,
      slot_role_fallback_used
        ? 'Fallback used (planned role inactive or exhausted).'
        : 'No fallback.'
    ].join(' ');

    picks.push({
      pick_nr,

      slot_role_planned: plannedRole,
      slot_role_used: budgetTrack,
      slot_role_fallback_used,
      slot_role_fallback_reason,

      top_need_family: topNeed.family,
      top_need_selection_mode,
      need_label: topNeed.label,
      need_dynamic_score: Number(
        n(topNeed.roleWeightedImportance || topNeed.dynamicImportance || 0).toFixed(2)
      ),

      player_name: s(bestCandidate?.name || '—'),
      klasse: s(bestCandidate?.klasse || '—'),
      color: candColor || '',
      rasse: s(bestCandidate?.rasse || '—'),

      budget_track_requested: requestedTrack,
      budget_track: budgetTrack,

      lane_budget_total: Number(n(laneCtx.lane_budget_total).toFixed(2)),
      lane_budget_remaining: Number(n(laneCtx.lane_budget_remaining).toFixed(2)),
      lane_slots_remaining: Number(n(laneCtx.lane_slots_remaining).toFixed(0)),
      lane_target_fee: Number(n(laneCtx.lane_target_fee).toFixed(2)),
      lane_min_fee: Number(n(laneCtx.lane_min_fee).toFixed(2)),
      lane_max_fee: Number(n(laneCtx.lane_max_fee).toFixed(2)),
      effective_pick_cap: Number(effective_pick_cap.toFixed(2)),

      market_role_min_fee: Number(n(laneCtx.market_role_min_fee).toFixed(2)),
      market_role_target_fee: Number(n(laneCtx.market_role_target_fee).toFixed(2)),
      market_role_max_fee: Number(n(laneCtx.market_role_max_fee).toFixed(2)),
      market_role_pool_count: Number(n(laneCtx.market_role_pool_count).toFixed(0)),

      player_bracket: bestExplain.player_bracket ?? null,
      preferred_bracket_min: bestExplain.preferred_bracket_min ?? null,
      preferred_bracket_max: bestExplain.preferred_bracket_max ?? null,
      bracket_fit_score: Number(n(bestExplain.bracket_fit_score).toFixed(2)),

      strategic_focus_matches: Array.isArray(bestExplain.matchedFocuses) ? bestExplain.matchedFocuses : [],
      multi_need_bonus: Number(n(bestExplain.multi_need_bonus).toFixed(2)),
      secondary_need_bonus: Number(n(bestExplain.secondary_need_bonus).toFixed(2)),
      score_jitter: Number(n(bestExplain.score_jitter).toFixed(3)),

      price: Number(price.toFixed(2)),
      budget_after: Number(Math.max(0, remainingBudget).toFixed(2)),

      budget_fit_score: Number(n(bestExplain.budget_fit_score).toFixed(2)),
      under_spend_penalty: Number(n(bestExplain.under_spend_penalty).toFixed(2)),
      over_spend_penalty: Number(n(bestExplain.over_spend_penalty).toFixed(2)),

      roster_size_after: baseRoster.length + picks.length + 1,
      score: Number(bestScore.toFixed(2)),
      rationale
    });
  }

  return {
    version: 'aiPlannedPicks.v4.3_hotfix',
    team,
    avg_slot_budget: n(plan?.avg_slot_budget),
    active_lanes: activeLanes,
    slot_plan_used: slotPlan,
    slots_simulated: picks.length,
    budget_start: Number(n(plan.allowed_budget_for_search).toFixed(2)),
    budget_remaining: Number(Math.max(0, remainingBudget).toFixed(2)),
    needs_rows_used: Array.isArray(aiNeedRows) ? aiNeedRows.length : 0,
    used_needs_fallback,
    needs_source,
    reason: picks.length > 0 ? 'ok' : 'no_pick_selected',
    picks
  };
})();

// term: aiTeamNeeds
// id: aiPreviewE2ETest
// type: datasource
// subtype: JavascriptQuery
// page: transfermarktPage
// folder: unknown
// updatedAt: unknown
// codeField: query
// dependencies: none
// extractionStatus: complete_or_primary_match
// Documentation:
//   After a successful purchase in the sequential package-buy flow, this query re-validates
//   the remaining queue against up-to-date state (cash, active players, transfer locks, roster size)
//   and advances to the next valid player. Invalid/unbuyable players are skipped.
// Returns:
//   {
//     status: 'stopped' | 'completed' | 'advanced' | 'skipped' | 'blocked',
//     index: number,
//     skipped: string[],
//     nextPlayerName: string | null,
//     reason?: string
//   }

if (!packageBuyFlowActive.value) {
  return {
    status: 'stopped',
    index: Number(packageBuyIndex.value || 0),
    skipped: [],
    nextPlayerName: null,
    reason: 'flow_not_active' };

}

const team = String(filterTeam.value || '').trim();
if (!team) {
  packageBuyFlowActive.setValue(false);
  return {
    status: 'blocked',
    index: Number(packageBuyIndex.value || 0),
    skipped: [],
    nextPlayerName: null,
    reason: 'no_team' };

}

const n = (v) => Number.isFinite(Number(v)) ? Number(v) : 0;
const norm = (v) => String(v ?? '').toLowerCase().trim();

// Always refresh key sources to avoid stale cash/locks
try {
  await Promise.all([
  getTeamsOverview.trigger(),
  getSaisonstandFromDB.trigger(),
  getAllActivePlayers.trigger(),
  getActivePlayersByTeam.trigger(),
  getTransfersFromDB.trigger(),
  getSoldPlayersCurrentSeason.trigger()]);

} catch (e) {
  // Non-fatal: continue with best-effort state
  console.warn('validateAutoBuyNextStep: refresh failed', e);
}

const cash = n(getCashFromSaisonstand.value?.cash || 0);
const season = Number(localStorage.values?.globalCurrentSeason || 1);

const transfers = Array.isArray(getTransfersFromDB.data) ?
getTransfersFromDB.data :
typeof formatDataAsArray === 'function' ?
formatDataAsArray(getTransfersFromDB.data) || [] :
[];

const sold = Array.isArray(getSoldPlayersCurrentSeason.data) ?
getSoldPlayersCurrentSeason.data :
typeof formatDataAsArray === 'function' ?
formatDataAsArray(getSoldPlayersCurrentSeason.data) || [] :
[];

const soldNames = new Set(sold.map((r) => norm(r?.player_name || r?.name)).filter(Boolean));

const allActive = Array.isArray(getAllActivePlayers.data) ?
getAllActivePlayers.data :
typeof formatDataAsArray === 'function' ?
formatDataAsArray(getAllActivePlayers.data) || [] :
[];

const activeNames = new Set(allActive.map((r) => norm(r?.name)).filter(Boolean));

const roster = Array.isArray(getActivePlayersByTeam.data) ?
getActivePlayersByTeam.data :
typeof formatDataAsArray === 'function' ?
formatDataAsArray(getActivePlayersByTeam.data) || [] :
[];

if (roster.length >= 12) {
  packageBuyFlowActive.setValue(false);
  packageBuyIndex.setValue(0);
  packageBuyQueue.setValue([]);
  packageBuySelection.setValue(null);
  utils.showNotification({
    title: 'Team voll',
    description: 'Team hat bereits 12 Spieler. Package-Flow gestoppt.',
    notificationType: 'warning',
    duration: 6 });

  return {
    status: 'blocked',
    index: Number(packageBuyIndex.value || 0),
    skipped: [],
    nextPlayerName: null,
    reason: 'roster_full' };

}

// Helper: player-based same-season lock
const hasPlayerTransferThisSeason = (playerName) => {
  const pn = norm(playerName);
  if (!pn) return false;
  return transfers.some((t) => norm(t?.player_name) === pn && Number(t?.season) === season);
};

// Resolve players list (source of truth)
const allPlayers = Array.isArray(playersTable.data) ?
playersTable.data :
typeof formatDataAsArray === 'function' ?
formatDataAsArray(playersTable.data) || [] :
[];

const findPlayer = (name) => allPlayers.find((r) => norm(r?.name) === norm(name)) || null;

const q = Array.isArray(packageBuyQueue.value) ? packageBuyQueue.value : [];
let idx = Number(packageBuyIndex.value || 0);

// Move to next index after a successful buy
idx = idx + 1;

const skipped = [];

while (idx < q.length) {
  const raw = q[idx];
  const name = raw?.name;
  if (!name) {
    skipped.push('(ungültiger Eintrag)');
    idx += 1;
    continue;
  }

  // Up-to-date object from playersTable (in case attributes changed)
  const playerObj = findPlayer(name) || raw;

  const fee = n(playerObj?.marktwert ?? playerObj?.mw ?? playerObj?.MW);

  // 1) Still exists + has a sensible price
  if (!(fee > 0)) {
    skipped.push(String(name));
    idx += 1;
    continue;
  }

  // 2) Enough cash
  if (fee > cash) {
    skipped.push(String(name));
    idx += 1;
    continue;
  }

  // 3) Player not already active somewhere
  if (activeNames.has(norm(name))) {
    skipped.push(String(name));
    idx += 1;
    continue;
  }

  // 4) Player-based season lock
  if (hasPlayerTransferThisSeason(name)) {
    skipped.push(String(name));
    idx += 1;
    continue;
  }

  // 5) Sold-this-season block (safety)
  if (soldNames.has(norm(name))) {
    skipped.push(String(name));
    idx += 1;
    continue;
  }

  // Found a valid next step
  packageBuyIndex.setValue(idx);
  frozenPurchasePlayer.setValue({ ...playerObj });

  // Keep UI consistent: open modal for next confirmation
  try {
    await getTeamsOverview.trigger();
  } catch (e) {}
  modalBuyPlayer.show();

  if (skipped.length) {
    utils.showNotification({
      title: 'Package weiter',
      description: `Übersprungen: ${skipped.slice(0, 3).join(', ')}${skipped.length > 3 ? '…' : ''}`,
      notificationType: 'info',
      duration: 6 });

  }

  return {
    status: skipped.length ? 'skipped' : 'advanced',
    index: idx,
    skipped,
    nextPlayerName: String(name) };

}

// No more players => complete
packageBuyFlowActive.setValue(false);
packageBuyIndex.setValue(0);
packageBuyQueue.setValue([]);
packageBuySelection.setValue(null);

utils.showNotification({
  title: 'Package Kauf abgeschlossen',
  description: skipped.length ?
  `Fertig. Übersprungen: ${skipped.slice(0, 3).join(', ')}${skipped.length > 3 ? '…' : ''}` :
  'Alle Spieler aus dem Package wurden durchgekauft.',
  notificationType: 'success',
  duration: 5 });


return { status: 'completed', index: idx, skipped, nextPlayerName: null };

// term: aiTeamNeeds
// id: aiSequentialNeedsPreview
// type: datasource
// subtype: JavascriptQuery
// page: transfermarktPage
// folder: unknown
// updatedAt: unknown
// codeField: query
// dependencies: none
// extractionStatus: complete_or_primary_match
return (async () => {
  try {
    const VERSION = 'aiSNP_debugSequentialChain.v4_score_factor_breakdown_clean';

    const n = (v) => Number.isFinite(Number(v)) ? Number(v) : 0;
    const s = (v) => String(v ?? '').trim();
    const lower = (v) => String(v ?? '').trim().toLowerCase();
    const arr = (v) => Array.isArray(v) ? v.filter(Boolean) : [];
    const obj = (v) => (v && typeof v === 'object' && !Array.isArray(v)) ? v : {};

    const runRef = async (name, ref, additionalScope = undefined) => {
      if (!ref) {
        return { ok: false, query: name, reason: 'query_not_found' };
      }

      if (typeof ref.trigger !== 'function') {
        return {
          ok: true,
          query: name,
          reason: 'no_trigger_using_cached_value',
          result: ref?.data ?? ref?.value ?? null
        };
      }

      try {
        const res = additionalScope
          ? await ref.trigger({ additionalScope })
          : await ref.trigger();

        return {
          ok: true,
          query: name,
          result: res ?? ref?.data ?? ref?.value ?? null
        };
      } catch (err) {
        return {
          ok: false,
          query: name,
          reason: 'trigger_failed',
          error: String(err?.message || err),
          stack: String(err?.stack || '')
        };
      }
    };

    const getRoleBenchData = () => {
      const src =
        (typeof aiSNP_roleBenchmarks !== 'undefined'
          ? (aiSNP_roleBenchmarks?.data ?? aiSNP_roleBenchmarks?.value ?? {})
          : {});

      const quick = obj(src?.quick_summary);
      const pct = obj(src?.mw_percentiles);

      return {
        core_from: n(quick?.core_from ?? src?.core ?? pct?.p55),
        depth_from: n(quick?.depth_from ?? src?.depth ?? pct?.p35),
        backup_from: n(quick?.backup_from ?? src?.backup ?? pct?.p25),
        reserve_below: n(quick?.reserve_below ?? src?.reserve_below ?? pct?.p15),
        star_from: n(quick?.star_from ?? src?.star ?? pct?.p87_5 ?? pct?.p875),
        superstar_from: n(quick?.superstar_from ?? src?.superstar ?? pct?.p97_5 ?? pct?.p975)
      };
    };

    const compactNeed = (row) => ({
      family: s(row?.family),
      type: s(row?.type),
      axis: s(row?.axis),
      diszi: s(row?.diszi),
      color: s(row?.color),
      label: s(row?.label),
      importance: Number(n(row?.importance).toFixed(2)),
      need01: Number(n(row?.need01).toFixed(3)),
      weighted_score: Number(n(row?.weighted_score ?? (n(row?.importance) * Math.max(0, n(row?.need01)))).toFixed(2))
    });

    const compactCandidate = (row, idx = 0) => ({
      rank: n(row?.rank || idx + 1),
      player_name: s(row?.player_name || row?.picked_player || row?.name),
      klasse: s(row?.klasse || row?.class),
      color: s(row?.color),
      price: Number(n(row?.price ?? row?.marktwert ?? row?.mw).toFixed(2)),
      fit: Number(n(row?.fit).toFixed(2)),
      score: Number(n(row?.score).toFixed(3)),
      matched_need_count: n(row?.matched_need_count ?? row?.matchedNeedCount),
      best_diszi_field: s(row?.best_diszi_field ?? row?.bestDisziField),
      best_diszi_score: Number(n(row?.best_diszi_score ?? row?.bestDisziScore).toFixed(2)),
      market_role: s(row?.market_role),
      role_band: s(row?.role_band),
      weighted_need_total: Number(n(row?.weighted_need_total).toFixed(3)),
      need_score_applied: Number(n(
        row?.need_score_applied ??
        row?.need_score_applied_current ??
        row?.need_score_current ??
        row?.need_score
      ).toFixed(3)),
      weighted_need_avg_per_need: Number(n(row?.weighted_need_avg_per_need).toFixed(3)),
      weighted_need_norm_guess_100: Number(n(row?.weighted_need_norm_guess_100).toFixed(3)),
      in_axis_hole_completion_bonus: Number(n(row?.in_axis_hole_completion_bonus).toFixed(2)),
      best_diszi_hole_solve_bonus: Number(n(row?.best_diszi_hole_solve_bonus ?? row?.bestDisziHoleSolveBonus).toFixed(2)),
      off_axis_detour_penalty: Number(n(row?.off_axis_detour_penalty).toFixed(2)),
      role_mismatch_penalty: Number(n(row?.role_mismatch_penalty).toFixed(2)),
      overpay_penalty: Number(n(row?.overpay_penalty).toFixed(2)),
      value_bonus: Number(n(row?.value_bonus).toFixed(2)),
      fit_penalty: Number(n(row?.fit_penalty ?? row?.negative_fit_penalty).toFixed(2)),
      score_jitter: Number(n(row?.score_jitter).toFixed(3)),
      top_axis_open_hole_pressure_01: Number(n(row?.top_axis_open_hole_pressure_01).toFixed(3)),
      identity_locked_hole_pressure_01: Number(n(row?.identity_locked_hole_pressure_01).toFixed(3)),
      blue_hole_pressure_01: Number(n(row?.blue_hole_pressure_01).toFixed(3)),
      value_signal_01: Number(n(row?.value_signal_01).toFixed(3)),
      identity_fit_01: Number(n(row?.identity_fit_01 ?? row?.identityFit01).toFixed(3))
    });

    const getChosenPickRow = (score) => {
      const chosen = obj(score?.chosen_pick);
      if (Object.keys(chosen).length) return chosen;

      const ranked = arr(score?.ranked_candidates);
      if (ranked.length) return ranked[0];

      if (s(score?.picked_player || score?.player_name)) {
        return {
          player_name: s(score?.picked_player || score?.player_name),
          klasse: s(score?.klasse),
          color: s(score?.color),
          price: n(score?.price),
          fit: n(score?.fit),
          score: n(score?.score),
          pre_jitter_score: n(score?.pre_jitter_score ?? score?.preJitterScore),
          preJitterScore: n(score?.pre_jitter_score ?? score?.preJitterScore),
          matched_need_count: n(score?.matched_need_count ?? score?.matchedNeedCount),
          matched_need_labels: arr(score?.matched_need_labels),
          best_diszi_field: s(score?.best_diszi_field ?? score?.bestDisziField),
          best_diszi_score: n(score?.best_diszi_score ?? score?.bestDisziScore),
          market_role: s(score?.market_role),
          role_band: s(score?.role_band),
          weighted_need_primary: n(score?.weighted_need_primary),
          weighted_need_secondary: n(score?.weighted_need_secondary),
          weighted_need_side: n(score?.weighted_need_side),
          weighted_need_total: n(score?.weighted_need_total),
          weighted_need_avg_per_need: n(score?.weighted_need_avg_per_need),
          weighted_need_norm_guess_100: n(score?.weighted_need_norm_guess_100),
          need_score_applied: n(score?.need_score_applied ?? score?.need_score_applied_current ?? score?.need_score_current ?? score?.need_score),
          best_diszi_hole_solve_bonus: n(score?.best_diszi_hole_solve_bonus ?? score?.bestDisziHoleSolveBonus),
          in_axis_hole_completion_bonus: n(score?.in_axis_hole_completion_bonus),
          off_axis_detour_penalty: n(score?.off_axis_detour_penalty),
          role_mismatch_penalty: n(score?.role_mismatch_penalty),
          overpay_penalty: n(score?.overpay_penalty),
          value_bonus: n(score?.value_bonus),
          fit_penalty: n(score?.fit_penalty ?? score?.negative_fit_penalty),
          hard_block_penalty: n(score?.hard_block_penalty),
          score_jitter: n(score?.score_jitter),
          top_axis_open_hole_pressure_01: n(score?.top_axis_open_hole_pressure_01),
          identity_locked_hole_pressure_01: n(score?.identity_locked_hole_pressure_01),
          blue_hole_pressure_01: n(score?.blue_hole_pressure_01),
          value_signal_01: n(score?.value_signal_01),
          identity_fit_01: n(score?.identity_fit_01 ?? score?.identityFit01)
        };
      }

      return {};
    };

    const buildWhyPicked = ({
      strategyKey,
      slotRolePlanned,
      marketRole,
      matchedNeedCount,
      bestDisziField,
      bestDisziScore,
      fit,
      valueBonus,
      valueSignal,
      topAxis,
      topColor,
      matchedNeedLabels,
      weightedNeedTotalRaw,
      weightedNeedAvgPerNeed,
      weightedNeedNormGuess100,
      needScoreApplied,
      bestDisziHoleSolveBonus,
      inAxisHoleCompletionBonus,
      offAxisDetourPenalty,
      roleMismatchPenalty,
      overpayPenalty,
      fitPenalty,
      topAxisOpenHolePressure01
    }) => {
      const reasons = [];

      if (strategyKey) reasons.push(`Strategie=${strategyKey}`);
      if (slotRolePlanned) reasons.push(`Slot=${slotRolePlanned}`);
      if (marketRole) reasons.push(`Role=${marketRole}`);
      if (matchedNeedCount > 0) reasons.push(`${matchedNeedCount} Need-Matches`);
      if (bestDisziField) reasons.push(`Best=${bestDisziField} (${Number(n(bestDisziScore).toFixed(1))})`);
      if (Number.isFinite(n(fit))) reasons.push(`Fit=${Number(n(fit).toFixed(2))}`);
      if (n(weightedNeedTotalRaw) > 0) reasons.push(`NeedRaw=${Number(n(weightedNeedTotalRaw).toFixed(2))}`);
      if (n(weightedNeedAvgPerNeed) > 0) reasons.push(`NeedAvg=${Number(n(weightedNeedAvgPerNeed).toFixed(2))}`);
      if (n(weightedNeedNormGuess100) > 0) reasons.push(`Need100~=${Number(n(weightedNeedNormGuess100).toFixed(2))}`);
      if (n(needScoreApplied) > 0) reasons.push(`NeedApplied=${Number(n(needScoreApplied).toFixed(2))}`);
      if (n(bestDisziHoleSolveBonus) > 0) reasons.push(`BestDisziBonus=${Number(n(bestDisziHoleSolveBonus).toFixed(2))}`);
      if (n(inAxisHoleCompletionBonus) > 0) reasons.push(`InAxisBonus=${Number(n(inAxisHoleCompletionBonus).toFixed(2))}`);
      if (n(offAxisDetourPenalty) > 0) reasons.push(`OffAxisMalus=${Number(n(offAxisDetourPenalty).toFixed(2))}`);
      if (n(roleMismatchPenalty) > 0) reasons.push(`RoleMalus=${Number(n(roleMismatchPenalty).toFixed(2))}`);
      if (n(overpayPenalty) > 0) reasons.push(`OverpayMalus=${Number(n(overpayPenalty).toFixed(2))}`);
      if (n(fitPenalty) > 0) reasons.push(`FitMalus=${Number(n(fitPenalty).toFixed(2))}`);
      if (n(topAxisOpenHolePressure01) > 0) reasons.push(`HolePressure=${Number(n(topAxisOpenHolePressure01).toFixed(3))}`);
      if (n(valueBonus) > 0) reasons.push(`ValueBonus=${Number(n(valueBonus).toFixed(2))}`);
      if (n(valueSignal) > 0) reasons.push(`ValueSignal=${Number(n(valueSignal).toFixed(3))}`);
      if (topAxis || topColor) reasons.push(`Fokus=${topAxis || '-'} / ${topColor || '-'}`);

      const labels = arr(matchedNeedLabels).filter(Boolean).slice(0, 3);
      if (labels.length) reasons.push(`Labels=${labels.join(' | ')}`);

      return reasons.join(' ; ');
    };

    const findCandidateRow = (candidatePool, pickedPlayer, pickedClass, pickedPrice) => {
      const nameNeedle = lower(pickedPlayer);
      const classNeedle = lower(pickedClass);

      const matches = arr(candidatePool).filter((row) => {
        const rowName = lower(row?.name || row?.player_name || row?.Name);
        if (rowName !== nameNeedle) return false;

        if (classNeedle) {
          const rowClass = lower(row?.klasse || row?.Klasse || row?.class);
          if (rowClass && rowClass !== classNeedle) return false;
        }

        return true;
      });

      if (!matches.length) return null;
      if (matches.length === 1) return matches[0];

      if (pickedPrice > 0) {
        const exact = matches.find((row) => {
          const rowPrice = n(
            row?.marktwert ||
            row?.market_value ||
            row?.mw ||
            row?.MW ||
            row?.price ||
            0
          );
          return Math.abs(rowPrice - pickedPrice) < 0.01;
        });
        if (exact) return exact;
      }

      return matches[0];
    };

    const refs = {
      planner: (typeof aiSNP_planner !== 'undefined' ? aiSNP_planner : null),
      strategy: (typeof aiSNP_strategyProfile !== 'undefined' ? aiSNP_strategyProfile : null),
      needsCore: (typeof aiSNP_needsCore !== 'undefined' ? aiSNP_needsCore : null),
      score: (typeof aiSNP_pickScoreEngine !== 'undefined' ? aiSNP_pickScoreEngine : null),
      roleBench: (typeof aiSNP_roleBenchmarks !== 'undefined' ? aiSNP_roleBenchmarks : null)
    };

    const existence = Object.entries(refs).map(([name, ref]) => ({
      query: name,
      exists: !!ref,
      hasTrigger: !!ref?.trigger
    }));

    const plannerRun = await runRef('aiSNP_planner', refs.planner);
    const planner = plannerRun?.result ?? {};

    if (!plannerRun?.ok || !planner?.ok) {
      return {
        ok: false,
        reason: 'planner_failed',
        existence,
        planner_run: plannerRun
      };
    }

    const strategyRun0 = await runRef('aiSNP_strategyProfile', refs.strategy, {
      simSeedInput: String(Date.now()),
      stepIdxInput: 0,
      simRosterInput: Array.isArray(getActivePlayersByTeam?.data) ? getActivePlayersByTeam.data : [],
      remainingBudgetInput: n(transfermarktSalaryBudgetLogic?.value?.budget_after_sales ?? getCashFromSaisonstand?.value?.cash ?? 0)
    });

    const strategy0 = strategyRun0?.result ?? {};

    const activeRoster = Array.isArray(getActivePlayersByTeam?.data) ? getActivePlayersByTeam.data : [];
    const candidatePool =
      Array.isArray(aiTransferCandidatePool?.value) ? aiTransferCandidatePool.value :
      Array.isArray(aiTransferCandidatePool?.data) ? aiTransferCandidatePool.data :
      [];

    const simRoster = [...activeRoster];
    const pickedNames = [];
    const laneSpent = { star: 0, core: 0, depth: 0, reserve: 0, diszi: 0 };

    let remainingBudget = n(
      transfermarktSalaryBudgetLogic?.value?.budget_after_sales ??
      getCashFromSaisonstand?.value?.cash ??
      0
    );

    const plannedSteps = n(planner?.planned_steps || 0);
    const simSeed = s(strategy0?.sim_seed || Date.now());
    const slotPlan = arr(planner?.slot_plan_used);

    const roleBench = getRoleBenchData();
    const step_debug_rows = [];

    for (let stepIdx = 0; stepIdx < plannedSteps; stepIdx++) {
      const plannedRole = s(slotPlan[stepIdx] || '');

      const scope = {
        simRosterInput: simRoster,
        pickedNamesInput: pickedNames,
        laneSpentInput: laneSpent,
        remainingBudgetInput: remainingBudget,
        stepIdxInput: stepIdx,
        plannedRoleInput: plannedRole,
        pickedCountInput: pickedNames.length,
        simSeedInput: simSeed
      };

      const strategyRun = await runRef('aiSNP_strategyProfile', refs.strategy, scope);
      const needsRun = await runRef('aiSNP_needsCore', refs.needsCore, scope);
      const scoreRun = await runRef('aiSNP_pickScoreEngine', refs.score, scope);

      const strategy = strategyRun?.result ?? {};
      const needs = needsRun?.result ?? {};
      const score = scoreRun?.result ?? {};

      if (!scoreRun?.ok || !score?.ok) {
        step_debug_rows.push({
          step: stepIdx + 1,
          slot_role_planned: plannedRole,
          stop_reason: score?.reason || scoreRun?.reason || 'score_failed',
          reason: score?.reason || '',
          error: score?.error || scoreRun?.error || '',
          top_axis: s(needs?.top_axis || needs?.topAxis || ''),
          active_need_count: n(needs?.active_need_count || needs?.activeNeeds?.length || 0)
        });
        break;
      }

      const chosen = getChosenPickRow(score);

      const pickedPlayer = s(chosen?.player_name || chosen?.picked_player);
      const pickedClass = s(chosen?.klasse);
      const pickedColor = s(chosen?.color);
      const pickedPrice = n(chosen?.price ?? chosen?.marktwert ?? chosen?.mw);
      const pickedFit = n(chosen?.fit);
      const pickedScore = n(chosen?.score);
      const preJitterScore = n(chosen?.pre_jitter_score ?? chosen?.preJitterScore);
      const matchedNeedCount = n(chosen?.matched_need_count ?? chosen?.matchedNeedCount);
      const matchedNeedLabels = arr(chosen?.matched_need_labels);
      const bestDisziField = s(chosen?.best_diszi_field ?? chosen?.bestDisziField);
      const bestDisziScore = n(chosen?.best_diszi_score ?? chosen?.bestDisziScore);
      const marketRole = s(chosen?.market_role);
      const roleBand = s(chosen?.role_band);
      const valueSignal = n(chosen?.value_signal_01);
      const valueBonus = n(chosen?.value_bonus);
      const identityFit = n(chosen?.identity_fit_01 ?? chosen?.identityFit01);
      const scoreJitter = n(chosen?.score_jitter);

      const weightedNeedPrimary = n(chosen?.weighted_need_primary ?? score?.weighted_need_primary);
      const weightedNeedSecondary = n(chosen?.weighted_need_secondary ?? score?.weighted_need_secondary);
      const weightedNeedSide = n(chosen?.weighted_need_side ?? score?.weighted_need_side);
      const weightedNeedTotal = n(chosen?.weighted_need_total ?? score?.weighted_need_total);
      const weightedNeedAvgPerNeed = n(chosen?.weighted_need_avg_per_need ?? score?.weighted_need_avg_per_need);
      const weightedNeedNormGuess100 = n(chosen?.weighted_need_norm_guess_100 ?? score?.weighted_need_norm_guess_100);

      const needScoreApplied = n(
        chosen?.need_score_applied ??
        chosen?.need_score_applied_current ??
        chosen?.need_score_current ??
        chosen?.need_score ??
        score?.need_score_applied ??
        score?.need_score_applied_current ??
        score?.need_score_current ??
        score?.need_score
      );

      const inAxisHoleCompletionBonus = n(chosen?.in_axis_hole_completion_bonus ?? score?.in_axis_hole_completion_bonus);
      const bestDisziHoleSolveBonus = n(
        chosen?.best_diszi_hole_solve_bonus ??
        chosen?.bestDisziHoleSolveBonus ??
        score?.best_diszi_hole_solve_bonus ??
        score?.bestDisziHoleSolveBonus
      );
      const offAxisDetourPenalty = n(chosen?.off_axis_detour_penalty ?? score?.off_axis_detour_penalty);
      const roleMismatchPenalty = n(chosen?.role_mismatch_penalty ?? score?.role_mismatch_penalty);
      const overpayPenalty = n(chosen?.overpay_penalty ?? score?.overpay_penalty);
      const fitPenalty = n(chosen?.fit_penalty ?? chosen?.negative_fit_penalty ?? score?.fit_penalty ?? score?.negative_fit_penalty);
      const hardBlockPenalty = n(
        chosen?.hard_block_penalty ??
        (chosen?.negative_fit_hard_block ? 9999 : 0) ??
        score?.hard_block_penalty ??
        (score?.negative_fit_hard_block ? 9999 : 0)
      );

      const topAxisOpenHolePressure01 = n(chosen?.top_axis_open_hole_pressure_01 ?? score?.top_axis_open_hole_pressure_01 ?? needs?.top_axis_open_hole_pressure_01);
      const identityLockedHolePressure01 = n(chosen?.identity_locked_hole_pressure_01 ?? score?.identity_locked_hole_pressure_01 ?? needs?.identity_locked_hole_pressure_01);
      const blueHolePressure01 = n(chosen?.blue_hole_pressure_01 ?? score?.blue_hole_pressure_01 ?? needs?.blue_hole_pressure_01);
      const topAxisOpenHoleCount = n(chosen?.top_axis_open_hole_count ?? score?.top_axis_open_hole_count ?? needs?.top_axis_open_hole_count);

      const topNeeds = arr(
        needs?.weighted_need_breakdown_top6 ||
        needs?.weighted_need_breakdown_top12 ||
        score?.top_needs_for_debug ||
        []
      ).slice(0, 6).map(compactNeed);

      const topCandidates = arr(score?.ranked_candidates).slice(0, 6).map((row, idx) => compactCandidate(row, idx));

      const positiveBlocks = [
        { block: 'weighted_need_total_raw', points: Number(weightedNeedTotal.toFixed(3)), note: 'Rohsumme aller Need-Beiträge der max. 15 Scoring-Needs' },
        { block: 'weighted_need_avg_per_need', points: Number(weightedNeedAvgPerNeed.toFixed(3)), note: 'Rohsumme / verwendete Need-Anzahl' },
        { block: 'weighted_need_norm_guess_100', points: Number(weightedNeedNormGuess100.toFixed(3)), note: 'grobe 0-100 Sicht via /10' },
        { block: 'need_score_applied_current', points: Number(needScoreApplied.toFixed(3)), note: 'aktueller Need-Beitrag im Score' },
        { block: 'best_diszi_hole_solve_bonus', points: Number(bestDisziHoleSolveBonus.toFixed(3)), note: 'Bonus für stärksten einzelnen Diszi-Need' },
        { block: 'in_axis_hole_completion_bonus', points: Number(inAxisHoleCompletionBonus.toFixed(3)), note: 'Extra-Bonus wenn Top-Axis-Loch direkt getroffen wird' },
        { block: 'value_bonus', points: Number(valueBonus.toFixed(3)), note: 'Bonus für gutes Preis-/Slot-Verhältnis' }
      ];

      const penaltyBlocks = [
        { block: 'fit_penalty', points: Number((-fitPenalty).toFixed(3)), note: 'Malus für negativen Teamfit' },
        { block: 'off_axis_detour_penalty', points: Number((-offAxisDetourPenalty).toFixed(3)), note: 'Malus für thematischen Umweg' },
        { block: 'role_mismatch_penalty', points: Number((-roleMismatchPenalty).toFixed(3)), note: 'Malus wenn Marktrolle nicht zum Slot passt' },
        { block: 'overpay_penalty', points: Number((-overpayPenalty).toFixed(3)), note: 'Preis-/Overpay-Malus' },
        { block: 'hard_block_penalty', points: Number((hardBlockPenalty ? -9999 : 0).toFixed(3)), note: '0 oder -9999' }
      ];

      const finalBlocks = [
        ...positiveBlocks,
        ...penaltyBlocks,
        { block: 'score_jitter', points: Number(scoreJitter.toFixed(3)), note: 'kleines Seed-Rauschen' },
        { block: 'pre_jitter_score', points: Number(preJitterScore.toFixed(3)), note: 'Score vor Jitter' },
        { block: 'final_score', points: Number(pickedScore.toFixed(3)), note: 'Score nach Jitter' }
      ];

      const why_picked = buildWhyPicked({
        strategyKey: s(strategy?.key || strategy?.strategy?.key || score?.debug?.strategy_key),
        slotRolePlanned: plannedRole,
        marketRole,
        matchedNeedCount,
        bestDisziField,
        bestDisziScore,
        fit: pickedFit,
        valueBonus,
        valueSignal,
        topAxis: s(needs?.top_axis || needs?.topAxis || score?.top_axis),
        topColor: s(needs?.top_color || needs?.topColor || score?.top_color),
        matchedNeedLabels,
        weightedNeedTotalRaw: weightedNeedTotal,
        weightedNeedAvgPerNeed,
        weightedNeedNormGuess100,
        needScoreApplied,
        bestDisziHoleSolveBonus,
        inAxisHoleCompletionBonus,
        offAxisDetourPenalty,
        roleMismatchPenalty,
        overpayPenalty,
        fitPenalty,
        topAxisOpenHolePressure01
      });

      step_debug_rows.push({
        step: stepIdx + 1,
        strategy_key: s(strategy?.key || strategy?.strategy?.key || score?.debug?.strategy_key),
        strategy_roll: Number(n(strategy?.strategy_roll || score?.debug?.strategy_roll).toFixed(5)),
        slot_role_planned: plannedRole,

        top_axis: s(needs?.top_axis || needs?.topAxis || score?.top_axis),
        top_color: s(needs?.top_color || needs?.topColor || score?.top_color),
        active_need_count: n(score?.active_need_count ?? needs?.active_need_count ?? arr(needs?.active_needs).length),
        primary_need_count: n(score?.primary_need_count ?? needs?.primary_need_count ?? arr(needs?.primary_needs).length),
        secondary_need_count: n(score?.secondary_need_count ?? needs?.secondary_need_count ?? arr(needs?.secondary_needs).length),
        side_need_count: n(score?.side_need_count ?? needs?.side_need_count ?? arr(needs?.side_needs).length),

        need_count_used_for_scoring: s(score?.need_count_used_for_scoring || 'aktuell max. 15 Needs pro Kandidat'),
        weighted_need_primary: Number(weightedNeedPrimary.toFixed(3)),
        weighted_need_secondary: Number(weightedNeedSecondary.toFixed(3)),
        weighted_need_side: Number(weightedNeedSide.toFixed(3)),
        weighted_need_total: Number(weightedNeedTotal.toFixed(3)),
        weighted_need_avg_per_need: Number(weightedNeedAvgPerNeed.toFixed(3)),
        weighted_need_norm_guess_100: Number(weightedNeedNormGuess100.toFixed(3)),
        need_score_applied: Number(needScoreApplied.toFixed(3)),

        top_axis_open_hole_count: topAxisOpenHoleCount,
        top_axis_open_hole_pressure_01: Number(topAxisOpenHolePressure01.toFixed(3)),
        identity_locked_hole_pressure_01: Number(identityLockedHolePressure01.toFixed(3)),
        blue_hole_pressure_01: Number(blueHolePressure01.toFixed(3)),
        in_axis_hole_completion_bonus: Number(inAxisHoleCompletionBonus.toFixed(2)),
        best_diszi_hole_solve_bonus: Number(bestDisziHoleSolveBonus.toFixed(2)),
        off_axis_detour_penalty: Number(offAxisDetourPenalty.toFixed(2)),
        role_mismatch_penalty: Number(roleMismatchPenalty.toFixed(2)),
        overpay_penalty: Number(overpayPenalty.toFixed(2)),
        fit_penalty: Number(fitPenalty.toFixed(2)),
        hard_block_penalty: hardBlockPenalty ? 9999 : 0,
        top_axis_open_hole_labels: arr(score?.top_axis_open_hole_labels || []).slice(0, 6),
        top_axis_open_hole_breakdown_top6: arr(score?.top_axis_open_hole_breakdown_top6 || []).slice(0, 6),

        picked_player: pickedPlayer,
        klasse: pickedClass,
        color: pickedColor,
        price: Number(pickedPrice.toFixed(2)),
        fit: Number(pickedFit.toFixed(2)),
        score: Number(pickedScore.toFixed(3)),
        pre_jitter_score: Number(preJitterScore.toFixed(3)),
        score_jitter: Number(scoreJitter.toFixed(3)),
        market_role: marketRole,
        role_band: roleBand,
        matched_need_count: matchedNeedCount,
        matched_need_labels: matchedNeedLabels,
        best_diszi_field: bestDisziField,
        best_diszi_score: Number(bestDisziScore.toFixed(2)),
        identity_fit_01: Number(identityFit.toFixed(3)),
        why_picked,

        score_factor_breakdown: finalBlocks,

        pre_pick_context: {
          strategy: {
            key: s(strategy?.key || strategy?.strategy?.key || score?.debug?.strategy_key),
            strategy_roll: Number(n(strategy?.strategy_roll || score?.debug?.strategy_roll).toFixed(5)),
            quality_bias: Number(n(strategy?.quality_bias || score?.debug?.strategy_quality_bias).toFixed(3)),
            value_bias: Number(n(strategy?.value_bias || score?.debug?.strategy_value_bias).toFixed(3)),
            depth_bias: Number(n(strategy?.depth_bias).toFixed(3)),
            reserve_bias: Number(n(strategy?.reserve_bias).toFixed(3)),
            identity_bias: Number(n(strategy?.identity_bias || score?.debug?.strategy_identity_bias).toFixed(3)),
            hole_bias: Number(n(strategy?.hole_bias || score?.debug?.strategy_hole_bias).toFixed(3)),
            overpay_penalty_mult: Number(n(strategy?.overpay_penalty_mult || score?.debug?.strategy_overpay_penalty_mult).toFixed(3)),
            role_mismatch_mult: Number(n(strategy?.role_mismatch_mult || score?.debug?.strategy_role_mismatch_mult).toFixed(3)),
            star_tolerance: Number(n(strategy?.star_tolerance).toFixed(3))
          },
          needs: {
            top_axis: s(needs?.top_axis || needs?.topAxis || score?.top_axis),
            top_color: s(needs?.top_color || needs?.topColor || score?.top_color),
            active_need_count: n(score?.active_need_count ?? needs?.active_need_count ?? arr(needs?.active_needs).length),
            primary_need_count: n(score?.primary_need_count ?? needs?.primary_need_count ?? arr(needs?.primary_needs).length),
            secondary_need_count: n(score?.secondary_need_count ?? needs?.secondary_need_count ?? arr(needs?.secondary_needs).length),
            side_need_count: n(score?.side_need_count ?? needs?.side_need_count ?? arr(needs?.side_needs).length),
            weighted_need_primary_ctx: Number(n(score?.weighted_need_primary_ctx ?? needs?.weighted_need_primary_ctx).toFixed(3)),
            weighted_need_secondary_ctx: Number(n(score?.weighted_need_secondary_ctx ?? needs?.weighted_need_secondary_ctx).toFixed(3)),
            weighted_need_side_ctx: Number(n(score?.weighted_need_side_ctx ?? needs?.weighted_need_side_ctx).toFixed(3)),
            weighted_need_total_ctx: Number(n(score?.weighted_need_total_ctx ?? needs?.weighted_need_total_ctx).toFixed(3)),
            top_axis_open_hole_count: topAxisOpenHoleCount,
            top_axis_open_hole_pressure_01: Number(topAxisOpenHolePressure01.toFixed(3)),
            identity_locked_hole_pressure_01: Number(identityLockedHolePressure01.toFixed(3)),
            blue_hole_pressure_01: Number(blueHolePressure01.toFixed(3)),
            top_needs: topNeeds
          },
