      identity_locked_hole_pressure_01: topAxisOpenHolePressure01,
      blue_hole_pressure_01: Number(
        clamp(
          disziNeeds
            .filter((x) => x.axis === 'men' && x.need01 >= 0.35)
            .reduce((acc, x) => acc + n(x.need01), 0) / 2.4,
          0,
